const wrap = $input.first().json;

if (!wrap || wrap.error || wrap.status === "error") {
  return [{ json: { control: "SSL/TLS configuration", result: "Fail", risk: "High", notes: "SSL info API unavailable — cannot verify certificate. All HTTPS connections are unverifiable, risking interception and MITM attacks." } }];
}

const raw = wrap.data ? wrap.data : wrap;
const input = Array.isArray(raw)
  ? raw.find(i => i.domain_cert_status || i.certificate || i.domain) || raw[0]
  : raw;

const cert = input?.certificate;

// ---------------- NORMALIZE FIELDS (flat OR legacy cert object) ----------------
const daysLeft = input?.domain_days_remaining
  ?? input?.certificate?.details?.validity?.days_left
  ?? null;

const certStatus = input?.domain_cert_status || null;

const keyAlgo = input?.domain_key_algorithm
  || input?.certificate?.details?.public_key?.algorithm
  || null;

const keySize = input?.domain_key_size
  || input?.certificate?.details?.public_key?.size
  || null;

const keyStrength = input?.domain_key_strength || null;

const caIssuer = input?.domain_issuer_org
  || cert?.details?.issuer?.organization
  || null;

const certType = input?.domain_cert_type
  || cert?.type
  || null;

// isTrusted: use explicit flag if present, else fall back to cert.valid
const caTrustedRaw = input?.domain_ca_trusted ?? input?.ip_ca_trusted ?? null;
const isTrusted = caTrustedRaw !== null
  ? caTrustedRaw === true
  : (cert?.valid === true && cert?.blacklisted === false);

const validUntil = input?.domain_valid_until
  || cert?.details?.validity?.valid_to
  || null;

const subjectOrg = input?.domain_subject_org
  || cert?.details?.subject?.organization
  || null;

const issues = input?.issues || [];

// ---------------- CHECKS ----------------
const isExpiryCritical = certStatus === "CRITICAL"
  || (daysLeft !== null && daysLeft <= 7);

const isExpiryWarning = !isExpiryCritical
  && daysLeft !== null
  && daysLeft > 7
  && daysLeft <= 30;

// Key strength: explicit flag → algo+size → assume strong if no data at all
const isKeyStrong = keyStrength === "STRONG"
  ? true
  : keyAlgo && keySize
    ? (
        (["EC", "ECDSA"].includes(keyAlgo) && keySize >= 256) ||
        (keyAlgo === "RSA" && keySize >= 2048)
      )
    : keyStrength === null && keyAlgo === null
      ? true  // no key data = don't penalize, assume ok
      : false;

// Legacy cert-level validity checks
const legacyCertFailed = cert
  ? (!cert.valid || cert.expired || cert.revoked || !cert.name_match || cert.blacklisted)
  : false;

const isValidCert = !legacyCertFailed && isTrusted && !isExpiryCritical;

// ---------------- RESULT ----------------
let result, risk, notes;

if (isValidCert && isKeyStrong && !isExpiryCritical) {
  result = "Pass";
  risk = "Low";
  notes = [
    `✅ Valid ${certType || "OV"} certificate`,
    caIssuer ? `Issued by ${caIssuer}` : null,
    keyAlgo ? `${keyAlgo}${keySize ? ` ${keySize}-bit` : ""} key — ${keyStrength || "STRONG"}` : null,
    daysLeft !== null ? `Expires ${validUntil ? validUntil.split(" ")[0] : "N/A"} (${daysLeft}d remaining)` : null
  ].filter(Boolean).join(" · ");

} else {
  result = "Fail";

  const failedChecks = [];
  const impacts = [];

  if (isExpiryCritical) {
    failedChecks.push(`expires in ${daysLeft !== null ? daysLeft + "d" : "unknown"} (${validUntil ? validUntil.split(" ")[0] : "unknown date"})`);
    impacts.push("browsers will block access and show security warnings");
  } else if (isExpiryWarning) {
    failedChecks.push(`nearing expiry — ${daysLeft}d remaining`);
    impacts.push("imminent expiry risk if not renewed");
  }
  if (!isTrusted) {
    failedChecks.push("untrusted certificate authority");
    impacts.push("flagged as untrusted, exposing users to MITM attacks");
  }
  if (!isKeyStrong && (keyAlgo || keySize)) {
    failedChecks.push(`weak key (${keyAlgo || "unknown"}, ${keySize || "?"}bit)`);
    impacts.push("vulnerable to cryptographic attacks");
  }
  if (cert?.revoked) {
    failedChecks.push("certificate revoked");
    impacts.push("all encrypted traffic at risk");
  }
  if (cert?.expired) {
    failedChecks.push("certificate expired");
    impacts.push("site unreachable over HTTPS");
  }
  if (cert && !cert.name_match) {
    failedChecks.push("hostname mismatch");
    impacts.push("possible misconfiguration or spoofing");
  }
  if (cert?.blacklisted) {
    failedChecks.push("certificate blacklisted");
    impacts.push("certificate explicitly distrusted by security authorities");
  }
  issues.forEach(i => failedChecks.push(i));

  risk = (isExpiryCritical || !isTrusted || cert?.revoked || cert?.blacklisted)
    ? "High"
    : (isExpiryWarning || !isKeyStrong)
      ? "Medium"
      : "High";

  const orgLabel = subjectOrg ? ` for ${subjectOrg}` : "";
  const issuerLabel = caIssuer ? `, issued by ${caIssuer}` : "";

  notes = `SSL/TLS certificate${orgLabel}${issuerLabel} failed validation. `
    + `Issues: ${failedChecks.length ? failedChecks.join(", ") : "unknown"}. `
    + `Impact: ${impacts.length ? impacts.join(", ") : "encrypted traffic integrity at risk"}. `
    + `Immediate remediation required.`;
}

return [{ json: { control: "SSL/TLS configuration", result, notes, risk } }];

const items = $input.all().map(i => i.json);

// -------------------- EXTRACT INPUT --------------------
let scoring = null;
let ai = null;
let domain = null;
const controls = [];
const complianceItems = [];

for (const item of items) {
  if (item.parameter_scores && item.overall_score) scoring = item;
  else if (item.control && item.result) controls.push(item);
  else if (item.output) ai = JSON.parse(item.output);
  else if (item.domain) domain = item.domain;
  else if (item.requirement && item.control && item.status) complianceItems.push(item);
}

if (!scoring) {
  scoring = {
    parameter_scores: {},
    overall_score: "0 / 0",
    decision: "Pending"
  };
}

if (controls.length === 0) {
  controls.push({
    control: "Validation",
    result: "Pending",
    notes: "No scan data available",
    risk: "N/A"
  });
}

// -------------------- COUNT RESULTS --------------------
let passCount = 0;
let failCount = 0;
let warnCount = 0;

for (const c of controls) {
  if (c.result === "Pass") passCount++;
  else if (c.result === "Fail") failCount++;
  else warnCount++;
}

// -------------------- CALCULATE ACTUAL TOTAL SCORE --------------------
const sectionScores = Object.values(scoring.parameter_scores || {});
const numberOfSections = sectionScores.length || 1;
const maxPossibleScore = numberOfSections * 10;

let actualTotal = 0;
for (const score of sectionScores) {
  actualTotal += parseInt(score) || 0;
}

const scorePercentage = maxPossibleScore > 0 ? (actualTotal / maxPossibleScore) * 100 : 0;
scoring.overall_score = `${actualTotal} / ${maxPossibleScore}`;

// -------------------- USE DECISION FROM RISK SCORING NODE --------------------
const decision = scoring.decision || "Pending";

let riskLevel = "Low Risk";
if (decision === "Approved") {
  riskLevel = "Low Risk";
} else if (decision === "Approved (Conditional)") {
  riskLevel = "Medium Risk";
} else if (decision === "Needs Improvement") {
  riskLevel = "Medium Risk";
} else {
  riskLevel = "Critical Risk";
}

// -------------------- GROUP CONTROLS --------------------
const GROUPS = {
  "A. Website & Application Security": [
    "SSL/TLS configuration",
    "TLS protocol configuration",
    "Security Headers Configuration",
    "Cookie Security",
    "Mixed Content",
    "Web Vulnerability Baseline"
  ],
  "B. Infrastructure & Exposure": [
    "IP reputation and exposure",
    "Port Exposure",
    "CDN / Edge Protection Presence"
  ],
  "C. Merchant Domain & Reputation": [
    "Domain age and registration",
    "Domain & Reputation Assessment",
    "Domain Blacklist & Reputation"
  ],
  "D. DNS & Email Security": [
    "DNS hygiene and configuration",
    "Email security – SPF",
    "Email security – DKIM",
    "Email security – DMARC"
  ],
  "E. Advanced Assessment": [
    "WHOIS Transparency",
    "CMS / Platform Detection",
    "Plugins / CMS Exposure",
    "Third Party JS"
  ]
};

// -------------------- HELPERS --------------------
const badge = r => {
  if (r === "Pass") return `<span class="badge badge-pass">✓ Pass</span>`;
  if (r === "Fail") return `<span class="badge badge-fail">✗ Fail</span>`;
  if (r === "Not Assessed") return `<span class="badge badge-na">⊘ Not Assessed</span>`;
  return `<span class="badge badge-warn">⚠ Warn</span>`;
};

const risk = r => {
  if (!r || r === "N/A") return `<span class="risk-na">N/A</span>`;
  const level = r.toLowerCase();
  return `<span class="risk-${level}">${r}</span>`;
};

// -------------------- FINDINGS HTML --------------------
let findingsHTML = "";

for (const [section, names] of Object.entries(GROUPS)) {
  findingsHTML += `<div class="findings-section"><h4>${section}</h4><div class="controls-table">`;

  findingsHTML += `
    <div class="table-header">
      <div>Control</div>
      <div>Result</div>
      <div>Notes</div>
      <div>Risk</div>
    </div>`;

  for (const name of names) {
    const c = controls.find(x => x.control === name);

    if (!c) {
      findingsHTML += `
    <div class="table-row">
      <div class="control-name">${name}</div>
      <div class="result-cell">${badge("Not Assessed")}</div>
      <div class="notes-cell">This version does not support this scan. Please contact the SwiftSane team for an update.</div>
      <div class="risk-cell">${risk("N/A")}</div>
    </div>`;
    } else {
      findingsHTML += `
    <div class="table-row">
      <div class="control-name">${c.control}</div>
      <div class="result-cell">${badge(c.result)}</div>
      <div class="notes-cell">${c.notes || '-'}</div>
      <div class="risk-cell">${risk(c.risk)}</div>
    </div>`;
    }
  }

  findingsHTML += `</div></div>`;
}

// -------------------- SECTION SCORES --------------------
let scoringRows = "";
if (scoring.parameter_scores && Object.keys(scoring.parameter_scores).length > 0) {
  for (const [section, score] of Object.entries(scoring.parameter_scores)) {
    scoringRows += `
    <div class="score-row">
      <div class="score-label">${section}</div>
      <div class="score-value">${score} / 10</div>
    </div>`;
  }
} else {
  scoringRows += `
    <div class="score-row">
      <div class="score-label">No scoring data available</div>
      <div class="score-value">N/A</div>
    </div>`;
}

// -------------------- COMPLIANCE MAPPING HTML --------------------
let complianceHTML = "";

if (complianceItems.length > 0) {
  const complianceBadge = status => {
    if (status === "Pass") return `<span class="badge badge-pass">✓ Pass</span>`;
    if (status === "Fail") return `<span class="badge badge-fail">✗ Fail</span>`;
    if (status === "Not Assessed") return `<span class="badge badge-na">⊘ Not Assessed</span>`;
    return `<span class="badge badge-warn">⚠ Warn</span>`;
  };

  const pciItems = complianceItems.filter(item => item.requirement !== 'RBI');
  const rbiItems = complianceItems.filter(item => item.requirement === 'RBI');

  // ---- PCI DSS Table ----
  if (pciItems.length > 0) {
    let pciRowsHTML = "";
    pciItems.forEach((item, idx) => {
      const isLast = idx === pciItems.length - 1;

      pciRowsHTML += `
        <div class="compliance-row pci-row${isLast ? ' last-row' : ''}">
          <div class="compliance-req">${item.requirement}</div>
          <div class="compliance-control">${item.control}</div>
          <div class="compliance-status">${complianceBadge(item.status)}</div>
          <div class="compliance-evidence">${item.evidence || '-'}</div>
        </div>`;
    });

    complianceHTML += `
    <div class="compliance-subsection">
      <h4>PCI DSS</h4>
      <div class="compliance-table pci-table">
        <div class="compliance-header pci-header">
          <div>Requirement</div>
          <div>Control</div>
          <div>Status</div>
          <div>Evidence</div>
        </div>
        ${pciRowsHTML}
      </div>
    </div>`;
  }

  // ---- RBI Due Diligence Table ----
  if (rbiItems.length > 0) {
    let rbiRowsHTML = "";
    rbiItems.forEach((item, idx) => {
      let controlName = item.control;
      if (controlName.startsWith('RBI ')) {
        controlName = controlName.substring(4);
      }
      const notes = item.notes || item.evidence || '-';
      const isLast = idx === rbiItems.length - 1;

      rbiRowsHTML += `
        <div class="compliance-row rbi-row${isLast ? ' last-row' : ''}">
          <div class="compliance-theme">${controlName}</div>
          <div class="compliance-status">${complianceBadge(item.status)}</div>
          <div class="compliance-notes">${notes}</div>
        </div>`;
    });

    complianceHTML += `
    <div class="compliance-subsection">
      <h4>RBI Due Diligence</h4>
      <div class="compliance-table rbi-table">
        <div class="compliance-header rbi-header">
          <div>Theme</div>
          <div>Status</div>
          <div>Notes</div>
        </div>
        ${rbiRowsHTML}
      </div>
    </div>`;
  }
}

// -------------------- RATIONALE & RECOMMENDATIONS --------------------
let rationaleHTML = "";
if (ai?.rationale?.length) {
  rationaleHTML = `<div class="subsection"><h5>Rationale</h5><ul class="bullet-list">`;
  ai.rationale.forEach(item => {
    rationaleHTML += `<li>${item}</li>`;
  });
  rationaleHTML += `</ul></div>`;
}

let recommendationsHTML = "";
if (ai?.recommendations?.length) {
  recommendationsHTML = `<div class="subsection"><h5>Recommendations</h5><ul class="bullet-list">`;
  ai.recommendations.forEach(item => {
    recommendationsHTML += `<li>${item}</li>`;
  });
  recommendationsHTML += `</ul></div>`;
}

// -------------------- CONDITIONS TO GO-LIVE --------------------
let conditionsHTML = "";

if (ai?.conditions_to_go_live?.length) {
  conditionsHTML = `
  <div class="conditions-section ${decision === 'Rejected' ? 'conditions-critical' : ''}">
    <h5>⚠️ Conditions to Go-Live (Must be completed within 30 days)</h5>
    <ul class="bullet-list">
      ${ai.conditions_to_go_live.map(c => `<li>${c}</li>`).join("")}
    </ul>
  </div>`;
} else {
  let conditionsList = [];

  if (decision === "Approved") {
    conditionsList = [
      "Maintain current security configurations and monitor for any degradation",
      "Implement continuous security monitoring and alerting systems",
      "Schedule quarterly security re-assessments to ensure ongoing compliance",
      "Document and maintain security incident response procedures"
    ];
  } else if (decision === "Needs Improvement") {
    conditionsList = [
      "Address all 'Fail' rated controls within 30 days",
      "Implement remediation plan for 'Warn' rated controls within 60 days",
      "Provide evidence of fixes before go-live approval",
      "Schedule follow-up security assessment after remediation"
    ];
  } else {
    conditionsList = [
      "🚨 CRITICAL: Address all failed security controls immediately",
      "Implement comprehensive security remediation plan with timeline",
      "No go-live permitted until score reaches minimum 45%",
      "Mandatory security re-assessment required after fixes",
      "Engage security team for remediation guidance and support"
    ];
  }

  conditionsHTML = `
  <div class="conditions-section ${decision === 'Rejected' ? 'conditions-critical' : ''}">
    <h5>${decision === 'Rejected' ? '🚨 CRITICAL - ' : ''}Conditions to Go-Live (Must be completed within 30 days)</h5>
    <ul class="bullet-list">
      ${conditionsList.map(c => `<li>${c}</li>`).join("")}
    </ul>
  </div>`;
}

const decisionClass = decision === "Approved" ? "approved" :
                      decision === "Needs Improvement" ? "warning" : "rejected";

const now = new Date();
const reportDate = now.toLocaleDateString('en-GB', { day: '2-digit', month: 'short', year: 'numeric' });
const reportTime = now.toLocaleTimeString('en-IN', { hour: '2-digit', minute: '2-digit', hour12: false, timeZone: 'Asia/Kolkata' });

const scannedDomain = ($('Validate & Init')?.first()?.json?.domain) || domain || 'merchant-example.com';

// -------------------- FINAL HTML --------------------
const html = `
<!DOCTYPE html>
<html>
<head>
<meta charset="utf-8">
<style>
* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

@page { 
  margin: 15mm;
  size: A4;
}

body {
  background: #ffffff;
  color: #1a1a1a;
  font-family: Arial, Helvetica, sans-serif;
  font-size: 13px;
  line-height: 1.6;
  padding: 20px;
}

.report-header {
  background: linear-gradient(135deg, #b01a2d 0%, #8a1523 100%);
  border: 2px solid #b01a2d;
  border-radius: 12px;
  padding: 24px 28px;
  margin-bottom: 20px;
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
}

.header-left {
  display: flex;
  align-items: center;
  gap: 16px;
  flex: 1;
}

.logo-box {
  width: 60px;
  height: 60px;
  border-radius: 50%;
  overflow: hidden;
  flex-shrink: 0;
  border: 2px solid #ffffff;
  background: #ffffff;
}

.logo-box img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

.header-title h1 {
  font-size: 22px;
  font-weight: 700;
  margin-bottom: 6px;
  color: #ffffff;
}

.header-meta {
  font-size: 11px;
  color: #ffffff;
  line-height: 1.7;
  opacity: 0.95;
}

.header-meta strong {
  color: #ffffff;
}

.domain-highlight {
  color: #b01a2d;
  font-weight: 600;
  background: #ffffff;
  padding: 2px 6px;
  border-radius: 4px;
}

