  padding: 10px 24px;
  border-radius: 24px;
  font-weight: 700;
  font-size: 14px;
  text-align: center;
  white-space: nowrap;
}

.decision-badge.approved { background: #004777; color: #ffffff; }
.decision-badge.warning  { background: #f59e0b; color: #ffffff; }
.decision-badge.rejected { background: #ef4444; color: #ffffff; }

.section-card {
  background: #ffffff;
  border: 2px solid #e5e7eb;
  border-radius: 12px;
  padding: 24px 28px;
  margin-bottom: 20px;
}

.section-card h3 {
  font-size: 18px;
  font-weight: 700;
  margin-bottom: 18px;
  color: #b01a2d;
  border-bottom: 3px solid #b01a2d;
  padding-bottom: 8px;
}

.section-card h4 {
  font-size: 15px;
  font-weight: 600;
  margin-bottom: 12px;
  margin-top: 20px;
  color: #1a1a1a;
}

