return [{ json: { html } }];

const items = $input.all().map(i => i.json);

// Initialize sections
let scoringParagraph = "";
let findingsParagraph = "";
let rbiCompliance = "";
let pciCompliance = "";

// Extract sections
for (const item of items) {

  if (typeof item.scoring_paragraph === "string") {
    scoringParagraph = item.scoring_paragraph.trim();
  }

  if (typeof item.paragraph_report === "string") {
    findingsParagraph = item.paragraph_report.trim();
  }

  if (typeof item.rbi_compliance_text === "string") {
    rbiCompliance = item.rbi_compliance_text.trim();
  }

  if (typeof item.pci_dss_compliance_text === "string") {
    pciCompliance = item.pci_dss_compliance_text.trim();
  }
}

// Fallbacks (never throw)
if (!scoringParagraph) {
  scoringParagraph = "Overall risk scoring summary unavailable.";
}

if (!findingsParagraph) {
  findingsParagraph = "Detailed control findings unavailable.";
}

// Build report
let combinedReport = `
${scoringParagraph}

====================================

${findingsParagraph}
`.trim();

// Optional sections
if (rbiCompliance) {
  combinedReport += `

====================================

${rbiCompliance}`;
}

if (pciCompliance) {
  combinedReport += `

====================================

${pciCompliance}`;
}

// Output
return [{
  json: {
    combined_report: combinedReport
  }
}];

const data = $input.first()?.json || {};

const parameterScores = data.parameter_scores || {};
const overallScore = data.overall_score || "N/A";
const rawScore = data.raw_score || "";
const decision = data.decision || "Undetermined";

let paragraph = `The overall cyber risk evaluation resulted in a final decision of ${decision}, with an aggregate score of ${overallScore}`;

if (rawScore) {
  paragraph += ` (raw score ${rawScore})`;
}

paragraph += `. `;

// Context sentence
if (decision === "Approved") {
  paragraph += `The assessment indicates strong security posture across evaluated controls. `;
} else if (decision.includes("Conditional")) {
  paragraph += `The assessment indicates generally acceptable security posture with some areas requiring improvement. `;
} else {
  paragraph += `The assessment identified significant security weaknesses. `;
}

// Parameter breakdown
const entries = Object.entries(parameterScores);

if (entries.length > 0) {
  paragraph += `Control-level scoring is as follows: `;
  for (const [parameter, score] of entries) {
    paragraph += `${parameter} scored ${score} out of 10. `;
  }
} else {
  paragraph += `Control-level scoring data is unavailable. `;
}

return [{
  json: {
    scoring_paragraph: paragraph.trim()
  }
}];

const items = $input.all().map(i => i.json);
let paragraph = "";
for (const c of items) {
  const control = c.control || "Unnamed control";
  const result = c.result || "Not Available";
  const notes = c.notes || "No additional observations available";
  const risk = c.risk || "Not Available";
  paragraph += `The control "${control}" was assessed as ${result}. `;
  paragraph += `Observations indicate that ${notes}. `;
  paragraph += `The associated risk level is ${risk}. `;
}
return [{
  json: {
    paragraph_report: paragraph.trim()
  }
}];

const items = $input.all();
const requirement = "RBI";
const control     = "Domain Legitimacy & Stability";
const evidence    = "WHOIS + DNS records";

const domainRaw  = items[0]?.json;  // full WHOIS
const domainAge  = items[1]?.json;  // domain age
const whoisArt   = items[2]?.json;  // WHOIS artifact

/* =========================
   DOMAIN HYGIENE CHECK
========================= */
let domainStatus = "Fail";
if (
  domainRaw?.domain_age_found    === true &&
  domainRaw?.domain_registered   === "yes" &&
  domainRaw?.domain_age_in_years >= 1 &&
  domainRaw?.whois_data_hidden   === false
) {
  domainStatus = "Pass";
}

/* =========================
   WHOIS TRANSPARENCY CHECK
========================= */
const tStatus = whoisArt?.whois_transparency?.status || "Unknown";
let whoisStatus = "Pass";
if (tStatus === "Hidden")              whoisStatus = "Fail";
else if (tStatus === "Partially Transparent") whoisStatus = "Warn";

/* =========================
   NAMESERVER / DNS CHECK
========================= */
const nameservers = domainRaw?.nameservers || [];
let dnsStatus = nameservers.length > 0 ? "Pass" : "Fail";

// DNSSEC unsigned → downgrade
if (dnsStatus === "Pass" && domainRaw?.dnssec === "unsigned") {
  dnsStatus = "Warn";
}

/* =========================
   DOMAIN AGE STABILITY
========================= */
const ageYears = domainAge?.domain_age_in_years || 0;
let ageStatus = "Pass";
if (ageYears < 1)      ageStatus = "Fail";
else if (ageYears < 2) ageStatus = "Warn";

/* =========================
   COMBINED DECISION LOGIC
========================= */
let status = "Pass";

if (
  domainStatus === "Fail" ||
  dnsStatus    === "Fail" ||
  ageStatus    === "Fail"
) {
  status = "Fail";
} else if (
  domainStatus === "Warn" ||
  dnsStatus    === "Warn" ||
  whoisStatus  === "Warn" ||
  ageStatus    === "Warn"
) {
  status = "Warn";
}

return [{
  json: {
    requirement,
    control,
    status,
    evidence
  }
}];

const items = $input.all();
const requirement = "RBI";
const control     = "RBI Secure TLS / HTTPS-only";
const evidence    = "SSL certificate + mixed content scan";

const sslItem    = items[0]?.json;
const mixedArt   = items[1]?.json;

/* =========================
   SSL STATUS
========================= */
let sslStatus = "Fail";
const cert = sslItem?.certificate;
if (
  cert?.found    === true &&
  cert.valid     === true &&
  cert.expired   === false &&
  cert.revoked   === false &&
  cert.name_match === true
) {
  const keyAlgo = cert.details?.public_key?.algorithm;
  const keySize = cert.details?.public_key?.size;
  const strongCrypto =
    (keyAlgo === "RSA"   && keySize >= 2048) ||
    (keyAlgo === "ECDSA" && keySize >= 256);
  if (strongCrypto) sslStatus = "Pass";
}

/* =========================
   MIXED CONTENT STATUS
========================= */
let mixedStatus = "Pass";
const totalInsecure = mixedArt?.mixed_content_summary?.total_insecure || 0;
const hdrProt       = mixedArt?.header_protections || {};
const hstsAbsent    = hdrProt.strict_transport_security?.status === "Absent";
const cspAbsent     = hdrProt.content_security_policy?.status  === "Absent";

if (totalInsecure > 0) {
  mixedStatus = "Fail";
} else if (hstsAbsent || cspAbsent) {
  mixedStatus = "Warn";
}

/* =========================
   CERT EXPIRY WARNING
========================= */
const daysLeft = cert?.details?.validity?.days_left || 999;
let expiryStatus = "Pass";
if (daysLeft <= 0)  expiryStatus = "Fail";
else if (daysLeft <= 30) expiryStatus = "Warn";

/* =========================
   COMBINED RBI DECISION
========================= */
let status = "Pass";

if (sslStatus === "Fail" || mixedStatus === "Fail" || expiryStatus === "Fail") {
  status = "Fail";
} else if (sslStatus === "Warn" || mixedStatus === "Warn" || expiryStatus === "Warn") {
  status = "Warn";
}

return [{
  json: {
    requirement,
    control,
    status,
    evidence
  }
}];

const items = $input.all();
const requirement = "RBI";
const control     = "RBI Reputation & Abuse Risk";
const evidence    = "IP + Domain + URL reputation scans";

let status = "Pass";

/* =========================
   1. IP REPUTATION
========================= */
const ipRep = items[0]?.json;

if (ipRep?.blacklists?.detections > 0) status = "Fail";

if (
  ipRep?.information?.is_spamhaus_drop === true ||
  ipRep?.information?.is_bogon         === true ||
  ipRep?.anonymity?.is_tor             === true ||
  ipRep?.anonymity?.is_vpn             === true
) {
  status = "Fail";
}

// Risk score threshold
if (ipRep?.risk_score?.result > 50) status = "Fail";
else if (ipRep?.risk_score?.result > 20 && status === "Pass") status = "Warn";

/* =========================
   2. URL REPUTATION
========================= */
const urlRep = items[1]?.json;

if (
  urlRep?.security_checks?.is_phishing_heuristic === true ||
  urlRep?.security_checks?.is_suspicious_content === true ||
  urlRep?.security_checks?.is_domain_blacklisted === true ||
  urlRep?.risk_score?.result > 0
) {
  status = "Fail";
}

/* =========================
   3. DOMAIN REPUTATION
========================= */
const domainRep = items[2]?.json;

if (
  domainRep?.blacklists?.detections > 0 ||
  domainRep?.security_checks?.is_domain_blacklisted === true ||
  domainRep?.risk_score?.result > 0
) {
  status = "Fail";
}

/* =========================
   FINAL OUTPUT
========================= */
return [{
  json: {
    requirement,
    control,
    status,
    evidence
  }
}];

const items = $input.all();
const requirement = "11.2";
const control     = "External Vulnerability Scanning";
const evidence    = "Port scan + web vulnerability baseline + CMS exposure + page artifacts";

const cmsArt   = items[0]?.json;
const baseline = items[1]?.json?.baseline_parameters;
const artifacts= items[2]?.json;
const portScan = items[3]?.json;

/* =========================
   PORT EXPOSURE CHECK
========================= */
const portData         = portScan?.result?.[0] || {};
const ports            = portData.ports || [];
const highRiskPorts    = [21, 23, 3389, 445];
const mediumRiskPorts  = [22, 3306, 5432, 6379, 27017];

const highRiskOpen   = ports.filter(p => highRiskPorts.includes(p.port));
const mediumRiskOpen = ports.filter(p => mediumRiskPorts.includes(p.port));

let portStatus = "Pass";
if (highRiskOpen.length > 0)   portStatus = "Fail";
else if (mediumRiskOpen.length > 0) portStatus = "Warn";

/* =========================
   SECURITY HEADERS CHECK
========================= */
const headersAbsent    = baseline?.security_headers?.headers_absent || 0;
const criticalMissing  = [
  baseline?.security_headers?.checks?.content_security_policy,
  baseline?.security_headers?.checks?.strict_transport_security,
  baseline?.security_headers?.checks?.x_frame_options
].filter(v => v === "Absent").length;

const serverExposed    = baseline?.security_headers?.information_exposure?.server?.status    === "Exposed";
const poweredByExposed = baseline?.security_headers?.information_exposure?.x_powered_by?.status === "Exposed";

let headersStatus = "Pass";
if (criticalMissing >= 2)                headersStatus = "Fail";
else if (criticalMissing === 1 || headersAbsent > 5) headersStatus = "Warn";

/* =========================
   CMS & PLUGIN EXPOSURE
========================= */
const pluginCount  = cmsArt?.wordpress_plugins?.count || 0;
const cmsDetected  = cmsArt?.cms_detection?.status === "Present";

let cmsStatus = "Pass";
if (pluginCount > 5)      cmsStatus = "Fail";
else if (pluginCount > 0 || cmsDetected) cmsStatus = "Warn";

/* =========================
   MIXED CONTENT CHECK
========================= */
const totalInsecure = baseline?.mixed_content?.total_insecure_resources || 0;
let mixedStatus = totalInsecure > 0 ? "Fail" : "Pass";

/* =========================
   EXTERNAL SCRIPTS CHECK
========================= */
const extScripts    = artifacts?.artifacts?.scripts_external?.count || 0;
let scriptStatus    = "Pass";
if (extScripts > 10)     scriptStatus = "Fail";
else if (extScripts > 0) scriptStatus = "Warn";

/* =========================
   TECH EXPOSURE
========================= */
let techStatus = "Pass";
if (serverExposed || poweredByExposed) techStatus = "Warn";

/* =========================
   FINAL PCI 11.2 DECISION
========================= */
let status = "Pass";

if (
  portStatus    === "Fail" ||
  headersStatus === "Fail" ||
  cmsStatus     === "Fail" ||
  mixedStatus   === "Fail" ||
  scriptStatus  === "Fail"
) {
  status = "Fail";
} else if (
  portStatus    === "Warn" ||
  headersStatus === "Warn" ||
  cmsStatus     === "Warn" ||
  scriptStatus  === "Warn" ||
  techStatus    === "Warn"
) {
  status = "Warn";
}

return [{
  json: {
    requirement,
    control,
    status,
    evidence
  }
}];

const items = $input.all();
const requirement = "6.6";
const control     = "WAF Protection (External Inference)";
const evidence    = "CDN/WAF fingerprint + headers + ASN + trust score";

const ipRep   = items[0]?.json;
const baseline = items[1]?.json?.baseline_parameters;

/* =========================
   CDN / WAF DETECTION
   from IP reputation data
========================= */
const isp         = (ipRep?.information?.isp          || "").toLowerCase();
const cloudProvider = (ipRep?.information?.cloud_provider || "").toLowerCase();
const edgeService = (ipRep?.information?.edge_service  || "").toLowerCase();
const reverseDns  = (ipRep?.information?.reverse_dns   || "").toLowerCase();
const asnName     = (ipRep?.asn?.asname               || "").toLowerCase();
const asnOrg      = (ipRep?.asn?.org                  || "").toLowerCase();
const isWebProxy  = ipRep?.anonymity?.is_webproxy      === true;
const isHosting   = ipRep?.anonymity?.is_hosting       === true;

const blob = `${isp} ${cloudProvider} ${edgeService} ${reverseDns} ${asnName} ${asnOrg}`;

const cdnVendors = [
  "cloudflare", "akamai", "fastly", "imperva", "incapsula",
  "sucuri", "barracuda", "cloudfront", "edgecast", "stackpath"
];
const hyperscalers = [
  "google", "amazon", "aws", "microsoft", "azure"
];
const hostnamePatterns = [
  "1e100.net", "googleusercontent", "cloudfront.net",
  "akamaiedge", "edgesuite", "fastly.net", "awsglobalaccelerator"
];

let wafDetected  = false;
let wafVendor    = null;

// CDN vendor match
const vendorMatch = cdnVendors.find(v => blob.includes(v));
if (vendorMatch) { wafDetected = true; wafVendor = vendorMatch; }

// Hyperscaler edge
if (!wafDetected) {
  const hyperMatch = hyperscalers.find(v => blob.includes(v));
  if (hyperMatch) { wafDetected = true; wafVendor = hyperMatch; }
}

// Hostname pattern
if (!wafDetected) {
