// -------------------- HELPERS --------------------
const escapeHtml = (text) => {
  if (!text) return '';
  return String(text)
    .replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;').replace(/'/g, '&#039;');
};

const formatJSON = (obj, indent = 0) => {
  if (obj === null) return '<span class="json-null">null</span>';
  if (obj === undefined) return '<span class="json-undefined">undefined</span>';
  const type = typeof obj;
  const spaces = '  '.repeat(indent);
  if (type === 'boolean') return `<span class="json-boolean">${obj}</span>`;
  if (type === 'number') return `<span class="json-number">${obj}</span>`;
  if (type === 'string') return `<span class="json-string">"${escapeHtml(obj)}"</span>`;
  if (Array.isArray(obj)) {
    if (obj.length === 0) return '<span class="json-bracket">[]</span>';
    let result = '<span class="json-bracket">[</span>\n';
    obj.forEach((item, i) => {
      result += spaces + '  ' + formatJSON(item, indent + 1);
      if (i < obj.length - 1) result += ',';
      result += '\n';
    });
    result += spaces + '<span class="json-bracket">]</span>';
    return result;
  }
  if (type === 'object') {
    const keys = Object.keys(obj);
    if (keys.length === 0) return '<span class="json-bracket">{}</span>';
    let result = '<span class="json-bracket">{</span>\n';
    keys.forEach((key, i) => {
      result += spaces + '  <span class="json-key">"' + escapeHtml(key) + '"</span>: ';
      result += formatJSON(obj[key], indent + 1);
      if (i < keys.length - 1) result += ',';
      result += '\n';
    });
    result += spaces + '<span class="json-bracket">}</span>';
    return result;
  }
  return escapeHtml(String(obj));
};

