const organizedData = {};

const push = (bucket, item) => {
  (organizedData[bucket] = organizedData[bucket] || []).push(item);
};

for (const item of items) {
  if (!item || Object.keys(item).length === 0) continue;
  if (item.parameter_scores || item.output || item.total_controls !== undefined) continue;

  if (item.parameter) {
    const bucket = PARAMETER_FIELD_MAP[item.parameter];
    if (bucket) { push(bucket, item); continue; }
  }

  if (item.control) {
    const bucket = CONTROL_FIELD_MAP[item.control];
    if (bucket) { push(bucket, item); continue; }
  }

  if (Array.isArray(item.result) && item.result.length > 0 && item.result[0].ports) {
    push('port_exposure', item); continue;
  }
}

