parameters.query:
SET NOCOUNT ON;
BEGIN TRANSACTION;

---------------------------------------------------
-- Inputs from n8n
---------------------------------------------------
DECLARE @assessment_id NVARCHAR(100) = '{{ $json.assessment_id }}';
DECLARE @user_id NVARCHAR(100) = '{{ $json.userId }}';
DECLARE @conversation_id NVARCHAR(100) = '{{ $json.conversation_id }}';
DECLARE @content NVARCHAR(MAX) = N'{{ $json.message }}';
DECLARE @response NVARCHAR(MAX) = N'{{ $json.response }}';

---------------------------------------------------
-- Handle empty/null values
---------------------------------------------------
IF @conversation_id IS NULL OR LTRIM(RTRIM(@conversation_id)) = ''
BEGIN
    SET @conversation_id =
        'conv-' +
        REPLACE(CONVERT(NVARCHAR(50), SYSDATETIME(), 126), ':', '') +
        '-' + RIGHT(CONVERT(NVARCHAR(50), NEWID()), 6);
END

IF @assessment_id IS NULL OR LTRIM(RTRIM(@assessment_id)) = ''
BEGIN
    SET @assessment_id = NULL;
END

IF @user_id IS NULL OR LTRIM(RTRIM(@user_id)) = ''
BEGIN
    SET @user_id = NULL;
END

---------------------------------------------------
-- Generate message_id
---------------------------------------------------
DECLARE @message_id NVARCHAR(100) =
    'msg-' +
    REPLACE(CONVERT(NVARCHAR(50), SYSDATETIME(), 126), ':', '') +
    '-' + RIGHT(CONVERT(NVARCHAR(50), NEWID()), 6);

---------------------------------------------------
-- Ensure assessment exists (if provided)
---------------------------------------------------
IF @assessment_id IS NOT NULL 
   AND NOT EXISTS (SELECT 1 FROM dbo.scans WHERE assessment_id = @assessment_id)
BEGIN
    INSERT INTO dbo.scans (assessment_id, user_id, status, created_at, updated_at)
    VALUES (@assessment_id, @user_id, 'active', SYSDATETIME(), SYSDATETIME());
END

---------------------------------------------------
-- Ensure conversation exists
---------------------------------------------------
IF NOT EXISTS (SELECT 1 FROM dbo.conversations WHERE id = @conversation_id)
BEGIN
    INSERT INTO dbo.conversations (id, assessment_id, user_id, created_at, updated_at)
    VALUES (@conversation_id, @assessment_id, @user_id, SYSDATETIME(), SYSDATETIME());
END
ELSE
BEGIN
    UPDATE dbo.conversations
    SET updated_at = SYSDATETIME(),
        assessment_id = COALESCE(@assessment_id, assessment_id),
        user_id = COALESCE(@user_id, user_id)
    WHERE id = @conversation_id;
END

---------------------------------------------------
-- Insert message
---------------------------------------------------
INSERT INTO dbo.messages (
    id,
    conversation_id,
    assessment_id,
    user_id,
    role,
    content,
    response,
    created_at
)
VALUES (
    @message_id,
    @conversation_id,
    @assessment_id,
    @user_id,
    'assistant',
    @content,
    @response,
    SYSDATETIME()
);

COMMIT TRANSACTION;

---------------------------------------------------
-- Return values to n8n
---------------------------------------------------
SELECT
    @conversation_id AS conversation_id,
    @message_id AS message_id,
    @assessment_id AS assessment_id;

