let merged = {};

for (const item of items) {
  const data = item.json;

  for (const key in data) {
    // If key doesn't exist, add it
    if (!(key in merged)) {
      merged[key] = data[key];
    } 
    // If key already exists and values are different
    else if (merged[key] !== data[key]) {
      // Convert to array to preserve both values
      if (!Array.isArray(merged[key])) {
        merged[key] = [merged[key]];
      }
      merged[key].push(data[key]);
    }
  }
}

// Return single merged object
return [
  {
    json: merged
  }
];

const output = {};

items.forEach(item => {
  const obj = item.json;

  // -----------------------------
  // CASE 1: PCI DSS requirement
  // -----------------------------
  if (obj.requirement && /^[0-9]+\.[0-9]+$/.test(obj.requirement)) {

    const reqId = obj.requirement.replace(/\./g, "_");
    const identifier = `pcidss_${reqId}`;

    Object.keys(obj).forEach(key => {
      if (key === "requirement") return;

      const newKey = `${key}_${identifier}`;
      output[newKey] = obj[key];
    });

    return; // skip normal processing
  }

  // -----------------------------
  // CASE 2: Normal identifier logic
  // -----------------------------
  let identifier = "";

  if (obj.control) {
    identifier = obj.control;
  } else if (obj.requirement) {
    identifier = obj.requirement;
  } else if (obj.conversation_id) {
    identifier = "metadata";
  } else if (obj.total_controls) {
    identifier = "summary";
  } else {
    identifier = "entry";
  }

  // Clean identifier
  identifier = identifier
    .replace(/[^a-zA-Z0-9]/g, "_")
    .replace(/_+/g, "_")
    .replace(/^_|_$/g, "");

  // Rename fields
  Object.keys(obj).forEach(key => {
    if (key === "control") return;

    const newKey = `${key}_${identifier}`;
    output[newKey] = obj[key];
  });

});

return [
  {
    json: output
  }
];

// N8N Code Node - Separate JSON Parameters

// Get input data
const inputData = $input.all();

