const wrap = $input.first().json;
const headers = wrap.headers || {};
const targetUrl = wrap.url || "";

let domain = "";
try { domain = new URL(targetUrl).hostname; } catch {}

// Normalize header keys
const h = {};
Object.keys(headers).forEach(key => { h[key.toLowerCase()] = headers[key]; });

// ===============================
// SCAN TIME (IST)
// ===============================
const now = new Date();
const scanDate = now.toLocaleDateString("en-IN", { timeZone: "Asia/Kolkata" });
const scanTime = now.toLocaleTimeString("en-IN", {
  timeZone: "Asia/Kolkata",
  hour: "2-digit",
  minute: "2-digit"
});

// ===============================
// GET COOKIES
// ===============================
let rawCookies = h["set-cookie"];

// No cookies at all
if (!rawCookies) {
  return [{
    json: {
      section: "A. WEBSITE & APPLICATION SECURITY",
      control: "Cookie Security – Technical Evidence",
      domain: domain,
      http_status: {
        code: wrap.statusCode || null,
        message: wrap.statusMessage || null
      },
      scan_information: {
        scan_date: scanDate,
        scan_time_IST: scanTime,
        document_type: "Technical Evidence & Raw Scan Data",
        purpose: "Supporting documentation for Cyber Risk Evaluation Report"
      },
      cookie_summary: {
        status:        "Absent",
        total_cookies: 0
      },
      cookie_analysis: [],
      raw_headers: headers
    }
  }];
}

// Ensure array
if (!Array.isArray(rawCookies)) rawCookies = [rawCookies];

// ===============================
// ANALYZE EACH COOKIE
// ===============================
const cookieReport = rawCookies.map(cookie => {
  const parts = cookie.split(";").map(p => p.trim());

  // Name & value
  const nameValue = parts[0] || "";
  const eqIndex = nameValue.indexOf("=");
  const cookieName  = eqIndex > -1 ? nameValue.substring(0, eqIndex).trim() : nameValue.trim();
  const cookieValue = eqIndex > -1 ? nameValue.substring(eqIndex + 1).trim() : "";

  // Flags
  const hasSecure   = parts.some(p => p.toLowerCase() === "secure");
  const hasHttpOnly = parts.some(p => p.toLowerCase() === "httponly");

  // SameSite
  const sameSitePart = parts.find(p => p.toLowerCase().startsWith("samesite"));
  const sameSiteValue = sameSitePart ? sameSitePart.split("=")[1]?.trim() || "present (no value)" : null;

  // Expiry
  const expiresPart = parts.find(p => p.toLowerCase().startsWith("expires"));
  const expiresValue = expiresPart ? expiresPart.split("=").slice(1).join("=").trim() : null;

  // Max-Age
  const maxAgePart = parts.find(p => p.toLowerCase().startsWith("max-age"));
  const maxAgeValue = maxAgePart ? maxAgePart.split("=")[1]?.trim() : null;

  // Path
  const pathPart = parts.find(p => p.toLowerCase().startsWith("path"));
  const pathValue = pathPart ? pathPart.split("=")[1]?.trim() : null;

  // Domain attribute
  const domainPart = parts.find(p => p.toLowerCase().startsWith("domain"));
  const domainValue = domainPart ? domainPart.split("=")[1]?.trim() : null;

  // Session vs Persistent
  const isPersistent = !!(expiresPart || maxAgePart);

  // Prefix detection (__Secure- / __Host-)
  const hasSecurePrefix = cookieName.startsWith("__Secure-");
  const hasHostPrefix   = cookieName.startsWith("__Host-");

  return {
    cookie_name: cookieName,
    cookie_value_preview: cookieValue.length > 30 ? cookieValue.substring(0, 30) + "..." : cookieValue,

    flags: {
      secure:    { status: hasSecure   ? "Present" : "Absent" },
      httponly:  { status: hasHttpOnly ? "Present" : "Absent" },
      samesite:  { status: sameSiteValue ? "Present" : "Absent", value: sameSiteValue },
    },

    attributes: {
      path:      { status: pathValue    ? "Present" : "Absent", value: pathValue },
      domain:    { status: domainValue  ? "Present" : "Absent", value: domainValue },
      expires:   { status: expiresValue ? "Present" : "Absent", value: expiresValue },
      max_age:   { status: maxAgeValue  ? "Present" : "Absent", value: maxAgeValue },
    },

    classification: {
      session_type:  isPersistent ? "Persistent" : "Session",
      secure_prefix: hasSecurePrefix ? "Present (__Secure-)" : hasHostPrefix ? "Present (__Host-)" : "Absent",
    },

    raw_value: cookie
  };
});

// ===============================
// SUMMARY COUNTS
// ===============================
const total          = cookieReport.length;
const secureCount    = cookieReport.filter(c => c.flags.secure.status    === "Present").length;
const httpOnlyCount  = cookieReport.filter(c => c.flags.httponly.status  === "Present").length;
const sameSiteCount  = cookieReport.filter(c => c.flags.samesite.status  === "Present").length;
const persistentCount= cookieReport.filter(c => c.classification.session_type === "Persistent").length;
const sessionCount   = total - persistentCount;

// ===============================
// BUILD ARTIFACT
// ===============================
const artifact = {
  section: "A. WEBSITE & APPLICATION SECURITY",
  control: "Cookie Security – Technical Evidence",
  domain: domain,

  http_status: {
    code: wrap.statusCode || null,
    message: wrap.statusMessage || null
  },

  scan_information: {
    scan_date: scanDate,
    scan_time_IST: scanTime,
    document_type: "Technical Evidence & Raw Scan Data",
    purpose: "Supporting documentation for Cyber Risk Evaluation Report"
  },

