// MIXED CONTENT DETECTION
// ===============================

const FALSE_POSITIVES = ["xmlns", "schema.org", "w3.org", "xmlsoap.org"];

function extractInsecure(pattern, label) {
  const matches = html.match(pattern) || [];
  return matches
    .filter(m => !FALSE_POSITIVES.some(fp => m.includes(fp)))
    .map(m => ({ type: label, value: m.trim() }));
}

// Scripts loaded over HTTP
const insecureScripts = extractInsecure(
  /<script[^>]+src=["']http:\/\/[^"']+["'][^>]*>/gi,
  "Script"
);

// Stylesheets loaded over HTTP
const insecureStyles = extractInsecure(
  /<link[^>]+href=["']http:\/\/[^"']+["'][^>]*>/gi,
  "Stylesheet"
);

// Images loaded over HTTP
const insecureImages = extractInsecure(
  /<img[^>]+src=["']http:\/\/[^"']+["'][^>]*>/gi,
  "Image"
);

// iFrames loaded over HTTP
const insecureIframes = extractInsecure(
  /<iframe[^>]+src=["']http:\/\/[^"']+["'][^>]*>/gi,
  "iFrame"
);

// Audio/Video loaded over HTTP
const insecureMedia = extractInsecure(
  /<(audio|video|source)[^>]+src=["']http:\/\/[^"']+["'][^>]*>/gi,
  "Media"
);

// Form actions posting over HTTP
const insecureForms = extractInsecure(
  /<form[^>]+action=["']http:\/\/[^"']+["'][^>]*>/gi,
  "Form Action"
);

// Generic src/href catch-all (catches anything missed above)
const genericInsecure = (html.match(/(src|href)=["']http:\/\/[^"']+/gi) || [])
  .filter(m => !FALSE_POSITIVES.some(fp => m.includes(fp)))
  .map(m => ({ type: "Other", value: m.trim() }));

// Merge all, dedupe by value
const allInsecure = [
  ...insecureScripts,
  ...insecureStyles,
  ...insecureImages,
  ...insecureIframes,
  ...insecureMedia,
  ...insecureForms,
  ...genericInsecure
];

const seen = new Set();
const dedupedInsecure = allInsecure.filter(item => {
  if (seen.has(item.value)) return false;
  seen.add(item.value);
  return true;
});

