// CONTENT SECURITY POLICY CHECK
// ===============================
const cspHeader = headers["content-security-policy"] || headers["Content-Security-Policy"] || null;
const upgradeInsecure = cspHeader?.includes("upgrade-insecure-requests") || false;
const blockMixed = cspHeader?.includes("block-all-mixed-content") || false;

