const scriptSrcs = dedupe(
  (html.match(/<script[^>]+src=["']([^"']+)["'][^>]*>/gi) || [])
    .map(tag => { const m = tag.match(/src=["']([^"']+)["']/i); return m ? m[1] : null; })
    .filter(Boolean)
);

const inlineScriptCount = (html.match(/<script(?![^>]*src=)[^>]*>[\s\S]*?<\/script>/gi) || []).length;

// ── 2. Stylesheets ──────────────────────────────────────────
const stylesheets = dedupe(
  (html.match(/<link[^>]+rel=["']stylesheet["'][^>]*>/gi) || [])
    .map(tag => { const m = tag.match(/href=["']([^"']+)["']/i); return m ? m[1] : null; })
    .filter(Boolean)
);

// ── 3. Images ───────────────────────────────────────────────
const images = dedupe(
  (html.match(/<img[^>]+>/gi) || [])
    .map(tag => { const m = tag.match(/src=["']([^"']+)["']/i); return m ? m[1] : null; })
    .filter(Boolean)
);

// ── 4. iFrames ──────────────────────────────────────────────
const iframes = dedupe(
  (html.match(/<iframe[^>]*>/gi) || [])
    .map(tag => { const m = tag.match(/src=["']([^"']+)["']/i); return m ? m[1] : "no-src"; })
    .filter(Boolean)
);

// ── 5. Forms ────────────────────────────────────────────────
const forms = (html.match(/<form[^>]*>/gi) || []).map(tag => {
  const action  = tag.match(/action=["']([^"']+)["']/i);
  const method  = tag.match(/method=["']([^"']+)["']/i);
  const enctype = tag.match(/enctype=["']([^"']+)["']/i);
  return {
    action:  action  ? action[1]  : "(none)",
    method:  method  ? method[1].toUpperCase() : "GET",
    enctype: enctype ? enctype[1] : "application/x-www-form-urlencoded"
  };
});

// ── 6. Meta Tags ────────────────────────────────────────────
const metaTags = (html.match(/<meta[^>]+>/gi) || []).map(tag => {
  const name      = tag.match(/name=["']([^"']+)["']/i);
  const prop      = tag.match(/property=["']([^"']+)["']/i);
  const httpEquiv = tag.match(/http-equiv=["']([^"']+)["']/i);
  const content   = tag.match(/content=["']([^"']+)["']/i);
  const charset   = tag.match(/charset=["']([^"']+)["']/i);
  return {
    key:     name ? name[1] : prop ? prop[1] : httpEquiv ? httpEquiv[1] : charset ? "charset" : "unknown",
    content: content ? content[1] : charset ? charset[1] : ""
  };
}).filter(m => m.key !== "unknown");

// ── 7. Links ────────────────────────────────────────────────
const allLinks = dedupe(
  (html.match(/href=["']([^"']+)["']/gi) || [])
    .map(h => { const m = h.match(/href=["']([^"']+)["']/i); return m ? m[1] : null; })
    .filter(Boolean)
);

