  if (l.startsWith("/") || l.startsWith("#") || l.startsWith("?")) return true;
  try { return new URL(l).hostname.endsWith(domain); } catch { return false; }
});

const externalLinks = allLinks.filter(l => {
  if (!l.startsWith("http")) return false;
  try { return !new URL(l).hostname.endsWith(domain); } catch { return false; }
});

