  (html.match(/<link[^>]+(rel=["'][^"']*icon[^"']*["'])[^>]*>/gi) || [])
    .map(tag => { const m = tag.match(/href=["']([^"']+)["']/i); return m ? m[1] : null; })
    .filter(Boolean)
);

// ── 10. Videos & Audio ──────────────────────────────────────
const videos = dedupe(
  (html.match(/<(video|source)[^>]+>/gi) || [])
    .map(tag => { const m = tag.match(/src=["']([^"']+)["']/i); return m ? m[1] : null; })
    .filter(Boolean)
);

