// 1. Security Headers
const sec        = bp.security_headers?.checks || {};
const infoExp    = bp.security_headers?.information_exposure || {};
const secAbsent  = bp.security_headers?.headers_absent || 0;

const criticalHeadersMissing = [
  sec.content_security_policy,
  sec.strict_transport_security,
  sec.x_frame_options
].filter(v => v === "Absent").length;

// 2. Cookie Security
const cookieStatus = bp.cookie_security?.cookies_present;
const cookieFlags  = bp.cookie_security?.flags || {};
const cookieFail   =
  cookieStatus === "Present" && (
    cookieFlags.secure?.status   === "Absent" ||
    cookieFlags.httponly?.status === "Absent"
  );

// 3. Mixed Content
const totalInsecure = bp.mixed_content?.total_insecure_resources || 0;
const hdrProt       = bp.mixed_content?.header_protections || {};

// 4. CMS & Plugin Exposure
const pluginCount  = bp.cms_plugin_exposure?.plugins?.count || 0;
const cmsDetected  = bp.cms_plugin_exposure?.cms?.status === "Present";
const serverExp    = infoExp.server?.status    === "Exposed";
const poweredByExp = infoExp.x_powered_by?.status === "Exposed";

// 5. Platform Detection
const totalIndicators = bp.platform_detection?.total_indicators || 0;

// 6. Port Exposure
const highRiskPorts   = bp.port_exposure?.high_risk_ports_open   || 0;
const mediumRiskPorts = bp.port_exposure?.medium_risk_ports_open || 0;
const totalPorts      = bp.port_exposure?.total_open_ports       || 0;

// ===============================
// BUILD FINDINGS
// ===============================
const highFindings   = [];
const mediumFindings = [];
const lowFindings    = [];

// Security Headers — Critical
if (criticalHeadersMissing >= 2) highFindings.push(`${criticalHeadersMissing} critical security headers missing (CSP, HSTS, X-Frame-Options)`);
else if (criticalHeadersMissing === 1) mediumFindings.push("1 critical security header missing");
if (secAbsent > 5) mediumFindings.push(`${secAbsent} security headers absent in total`);

// Information Exposure
if (serverExp)    lowFindings.push(`Server header exposed: ${infoExp.server?.value}`);
if (poweredByExp) lowFindings.push(`X-Powered-By exposed: ${infoExp.x_powered_by?.value}`);

// Mixed Content
if (totalInsecure > 0) highFindings.push(`${totalInsecure} insecure HTTP resources detected (mixed content)`);
if (hdrProt.csp    === "Absent") mediumFindings.push("CSP header absent — no mixed content protection");
if (hdrProt.hsts   === "Absent") mediumFindings.push("HSTS absent — HTTPS not enforced");

// Cookie Security
if (cookieFail) highFindings.push("Cookies missing Secure or HttpOnly flags");

// CMS & Plugins
if (pluginCount > 5)       highFindings.push(`${pluginCount} WordPress plugins exposed`);
else if (pluginCount > 0)  mediumFindings.push(`${pluginCount} WordPress plugins exposed`);
if (cmsDetected)           mediumFindings.push(`CMS detected: ${bp.cms_plugin_exposure?.cms?.detected?.join(", ")}`);

// Port Exposure
if (highRiskPorts > 0)   highFindings.push(`${highRiskPorts} high-risk port(s) open (FTP/Telnet/RDP/SMB)`);
if (mediumRiskPorts > 0) mediumFindings.push(`${mediumRiskPorts} sensitive service port(s) open (SSH/DB)`);
if (totalPorts > 0 && highRiskPorts === 0 && mediumRiskPorts === 0)
  lowFindings.push(`${totalPorts} port(s) open (web ports only)`);

// ===============================
// DECISION LOGIC
// ===============================
let result = "Pass";
let risk   = "Low";

if (highFindings.length >= 2) {
  result = "Fail";
  risk   = "High";
} else if (highFindings.length === 1) {
  result = "Fail";
  risk   = "High";
} else if (mediumFindings.length > 0) {
  result = "Warn";
  risk   = "Medium";
} else if (lowFindings.length > 0) {
  result = "Warn";
  risk   = "Low";
}

const allFindings = [...highFindings, ...mediumFindings, ...lowFindings];
const notes = allFindings.length
  ? allFindings.join(" | ")
  : "No significant vulnerabilities detected";

