const wrap = $input.first().json;

// ===============================
// INPUT NORMALIZATION
// ===============================
const raw = wrap.data ? wrap.data : wrap;
const arr = Array.isArray(raw) ? raw : [raw];

// Object 1: flat VT artifact (has domain_* fields)
const vtData = arr.find(i => i.whois_date_iso || i.has_whois || i.transparency_score) || {};

// Object 2: structured artifact (has whois_transparency, owner_details etc.)
const artifact = arr.find(i => i.whois_transparency) || {};

if (!vtData && !artifact) {
  return [{ json: { control: "WHOIS Transparency", result: "Fail", risk: "High", notes: "Artifact input unavailable or malformed" } }];
}

const transparency = artifact.whois_transparency || {};
const owner        = artifact.owner_details || {};
const registrar    = artifact.registrar_details || {};
const domain       = artifact.domain_details || {};

// ===============================
// NORMALIZE — pull from either source
// ===============================
const tStatus = transparency.status
  || (vtData.is_fully_redacted ? "Hidden"
    : vtData.is_partially_redacted ? "Partially Transparent"
    : vtData.has_whois ? "Fully Transparent"
    : "Hidden");

const orgPresent   = owner.organization?.status === "Present"
  || (vtData.redacted_fields?.registrant_company === false);

const countryPresent = owner.country?.status === "Present"
  || !!vtData.rdap_registrant_country
  || vtData.registrant_country === "United States";

const emailPresent = owner.email_domain?.status === "Present"
  || !!vtData.rdap_registrant_email
  || !!vtData.registrant_email;

const usingFreeEmail = owner.free_email?.value === true;

const dnssecSigned = vtData.dnssec_signed === true
  || domain.dnssec?.value === "signed";

const ageYears = domain.age_years?.value
  ?? (vtData.whois_create_date
    ? Math.floor((Date.now() - new Date(vtData.whois_create_date).getTime()) / (1000 * 60 * 60 * 24 * 365))
    : null);

const registrarPresent = registrar.registrar?.status === "Present"
  || !!vtData.rdap_registrar_name;

const abuseEmailPresent = registrar.abuse_email?.status === "Present"
  || !!vtData.rdap_abuse_email;

const privacyProxy = vtData.privacy_proxy === true;
const lockLevel    = vtData.lock_level || null;
const transparencyScore = vtData.transparency_score ?? null;
const vtIssues     = vtData.issues || [];

// ===============================
// BUILD FINDINGS
// ===============================
const issues = [];

if (tStatus === "Hidden" || privacyProxy) issues.push("WHOIS data hidden or privacy-proxied — owner identity concealed");
else if (tStatus === "Partially Transparent") issues.push("WHOIS partially redacted — owner details incomplete");

if (!orgPresent)     issues.push("Owner organization not disclosed");
if (!countryPresent) issues.push("Owner country not disclosed");
if (!emailPresent)   issues.push("Owner email not disclosed");
if (usingFreeEmail)  issues.push("Owner using free email provider — low accountability");

if (!dnssecSigned)   issues.push("DNSSEC unsigned — domain not cryptographically secured against DNS spoofing");

if (ageYears !== null && ageYears < 1)      issues.push("Domain less than 1 year old — newly registered, high risk");
else if (ageYears !== null && ageYears < 2) issues.push("Domain less than 2 years old — limited history");

if (!registrarPresent)   issues.push("Registrar information not available");
if (!abuseEmailPresent)  issues.push("No registrar abuse contact available");

// Pull any extra issues flagged by VT node
vtIssues.forEach(i => { if (!issues.includes(i)) issues.push(i); });

// ===============================
// DECISION LOGIC
// ===============================
let result, risk, notes;

const hardFail = tStatus === "Hidden" || privacyProxy || !orgPresent;
const warn     = tStatus === "Partially Transparent" || !dnssecSigned || usingFreeEmail;

if (hardFail) {
  result = "Fail";
  risk   = "High";
  const orgLabel   = artifact.host || vtData.domain || "this domain";
  const issuerNote = vtData.rdap_registrar_name ? `, registered via ${vtData.rdap_registrar_name}` : "";
  notes = `WHOIS transparency check failed for ${orgLabel}${issuerNote}. `
    + `Issues: ${issues.join("; ")}. `
    + `Impact: ownership cannot be verified, increasing risk of fraud, phishing, or untraceable abuse. `
    + `Immediate disclosure or registrar-level verification required.`;

} else if (warn) {
  result = "Warn";
  risk   = "Medium";
  notes = `WHOIS partially compliant. Issues: ${issues.join("; ")}. `
    + `Recommend enabling DNSSEC and ensuring full registrant disclosure.`;

} else if (issues.length > 0) {
  result = "Warn";
  risk   = "Low";
  notes = `WHOIS mostly transparent with minor gaps: ${issues.join("; ")}.`;

} else {
  result = "Pass";
  risk   = "Low";
  const orgName  = owner.organization?.value || vtData.rdap_registrant_email?.split("@")[1] || "verified org";
  const ageLabel = ageYears !== null ? `, domain age ${ageYears} years` : "";
  const lockLabel = lockLevel === "full_lock" ? ", full registry lock active" : "";
  notes = `✅ WHOIS fully transparent — registered to ${orgName}${ageLabel}${lockLabel}.`;
}

// ===============================
// RETURN
// ===============================
return [{ json: { control: "WHOIS Transparency", result, notes , risk} }];

