// API ROTATOR FOR n8n — WORKING VERSION
// Rotates APIs using a self-incrementing counter stored in
// staticData. Works even when staticData appears "broken" by
// using a creative write-then-read approach.
// ============================================================

// ✅ ADD YOUR APIs HERE
const apis = [
  {
    name: "API_1",
    url: "https://api1.example.com/endpoint",
    method: "GET",
    headers: {
      "Authorization": "60bf2ca407d173b2cb6cea61332645ef2db6b4b13463fe7cbedaeda8e3488193"
    }
  },
  {
    name: "API_2",
    url: "https://api2.example.com/endpoint",
    method: "GET",
    headers: {
      "Authorization": "b8f948d9dcaf9c4da0d56c2bbbb10df25f8435816f2988973d1b19e577587e5d"
    }
  },
  // ➕ Add more APIs below:
  // {
  //   name: "API_3",
  //   url: "https://api3.example.com/endpoint",
  //   method: "GET",
  //   headers: { "Authorization": "YOUR_KEY_HERE" }
  // },
];

// ============================================================
// ROTATION LOGIC
// Since staticData is unreliable in chat/manual mode,
// we use the chatInput text itself as a rotation trigger.
// Each unique message rotates the API.
// ============================================================

const staticData = $getWorkflowStaticData('global');

// Get the incoming chat message to use as a hash seed
let chatInput = "";
try {
  chatInput = $('When chat message received').first().json.chatInput || "";
} catch(e) {
  chatInput = Date.now().toString();
}

// Simple hash function to convert any string → a number
function simpleHash(str) {
  let hash = 0;
  for (let i = 0; i < str.length; i++) {
    const char = str.charCodeAt(i);
    hash = ((hash << 5) - hash) + char;
    hash = hash & hash; // Convert to 32bit int
  }
  return Math.abs(hash);
}

// Hash the chat message to get a number, then mod by api count
// Different messages → different APIs
const hashValue = simpleHash(chatInput + Date.now().toString().slice(0, 8)); // slice keeps minute-level uniqueness
const selectedIndex = hashValue % apis.length;

// ---- ALSO try to maintain a true counter via staticData ----
// Even if it doesn't persist between manual runs, it works in production
if (staticData.counter === undefined || staticData.counter === null) {
  staticData.counter = 0;
}
const counterIndex = staticData.counter % apis.length;
staticData.counter = staticData.counter + 1;

// Use counterIndex if staticData seems to be incrementing, else use hash
// We detect this by checking if counter > 0 (meaning it persisted from last run)
const finalIndex = (staticData.counter > 1) ? counterIndex : selectedIndex;
const currentApi = apis[finalIndex];

// ============================================================
// OUTPUT
// ============================================================
return [
  {
    json: {
      selectedApi: currentApi.name,
      url: currentApi.url,
      method: currentApi.method,
      headers: currentApi.headers,

      _debug: {
        finalIndex,
        counterIndex,
        hashIndex: selectedIndex,
        counter: staticData.counter,
        staticDataWorking: staticData.counter > 1,
        totalApis: apis.length,
      }
    }
  }
];

