const ipData = $input.all().find(item => item.json.data?.type === 'ip_address');
const domainData = $input.all().find(item => item.json.data?.type === 'domain');

const ipAttr     = ipData?.json.data.attributes;
const domainAttr = domainData?.json.data.attributes;

// ── KNOWN CDN PROVIDER LIST ──────────────────────────────────
const CDN_PROVIDERS = [
  'akamai', 'cloudflare', 'fastly', 'cloudfront', 'amazon',
  'azure', 'google', 'incapsula', 'imperva', 'sucuri',
  'stackpath', 'keycdn', 'bunnycdn', 'edgio', 'limelight'
];

// ── 1. FROM IP — AS OWNER ────────────────────────────────────
const asOwner    = ipAttr?.as_owner || '';
const asn        = ipAttr?.asn || null;
const ipNetwork  = ipAttr?.network || null;
const rdapName   = ipAttr?.rdap?.name || '';

const cdnFromAsOwner = CDN_PROVIDERS.find(c =>
  asOwner.toLowerCase().includes(c)
) || null;

// ── 2. FROM IP — SSL CERTIFICATE SAN ────────────────────────
// CDNs often show their own cert on the IP
const ipSslSubjectOrg = ipAttr?.last_https_certificate?.subject?.O || '';
const ipSslSubjectCN  = ipAttr?.last_https_certificate?.subject?.CN || '';
const ipSslIssuerOrg  = ipAttr?.last_https_certificate?.issuer?.O || '';
const ipSslSANs       = ipAttr?.last_https_certificate?.extensions?.subject_alternative_name || [];

const cdnFromIpSsl = CDN_PROVIDERS.find(c =>
  ipSslSubjectOrg.toLowerCase().includes(c) ||
  ipSslSubjectCN.toLowerCase().includes(c) ||
  ipSslSANs.some(s => s.toLowerCase().includes(c))
) || null;

// ── 3. FROM DOMAIN — NAMESERVERS ────────────────────────────
const nameservers = domainAttr?.rdap?.nameservers?.map(ns => ns.ldh_name) || [];

const cdnFromNameservers = CDN_PROVIDERS.find(c =>
  nameservers.some(ns => ns.toLowerCase().includes(c))
) || null;

// ── 4. FROM DOMAIN — DNS A RECORDS (IP RANGE CHECK) ─────────
const aRecords = (domainAttr?.last_dns_records || [])
  .filter(r => r.type === 'A')
  .map(r => r.value);

const aaaaRecords = (domainAttr?.last_dns_records || [])
  .filter(r => r.type === 'AAAA')
  .map(r => r.value);

// ── 5. FROM DOMAIN — TXT RECORDS (CDN VERIFICATION TOKENS) ──
const txtRecords = (domainAttr?.last_dns_records || [])
  .filter(r => r.type === 'TXT')
  .map(r => r.value);

const cdnTxtTokens = CDN_PROVIDERS.filter(c =>
  txtRecords.some(t => t.toLowerCase().includes(c))
);

// Specifically detect Fastly from TXT
const fastlyTxt = txtRecords.filter(t =>
  t.toLowerCase().includes('fastly')
);

// ── 6. FROM DOMAIN — DOMAIN SSL CERT SAN ────────────────────
const domainSslSubjectOrg = domainAttr?.last_https_certificate?.subject?.O || '';
const domainSslIssuerOrg  = domainAttr?.last_https_certificate?.issuer?.O || '';
const domainSslSANs       = domainAttr?.last_https_certificate?.extensions?.subject_alternative_name || [];

// ── 7. JARM FINGERPRINTS (both IP and domain) ────────────────
const ipJarm     = ipAttr?.jarm || null;
const domainJarm = domainAttr?.jarm || null;

// ── 8. FINAL CDN DETECTION ───────────────────────────────────
const detectedCdnSources = [];
if (cdnFromAsOwner)      detectedCdnSources.push({ source: 'ip_as_owner',     provider: cdnFromAsOwner,     value: asOwner });
if (cdnFromIpSsl)        detectedCdnSources.push({ source: 'ip_ssl_cert',     provider: cdnFromIpSsl,       value: ipSslSubjectOrg || ipSslSubjectCN });
if (cdnFromNameservers)  detectedCdnSources.push({ source: 'nameservers',     provider: cdnFromNameservers, value: nameservers.join(', ') });
if (cdnTxtTokens.length) detectedCdnSources.push({ source: 'txt_records',     provider: cdnTxtTokens.join(', '), value: fastlyTxt[0] || '' });

const cdnDetected  = detectedCdnSources.length > 0;
const cdnProviders = [...new Set(detectedCdnSources.map(s => s.provider))];

// ── OUTPUT ───────────────────────────────────────────────────
return [{
  json: {
    _node: 'CDN / Edge Protection Presence Artifacts — VT',

    // Final verdict
    cdn_detected:   cdnDetected,
    cdn_providers:  cdnProviders,
    detection_count: detectedCdnSources.length,

    // Evidence sources
    detection_sources: detectedCdnSources,

    // IP-level evidence
    ip_as_owner:        asOwner,
    ip_asn:             asn,
    ip_network:         ipNetwork,
    ip_rdap_name:       rdapName,
    ip_ssl_subject_org: ipSslSubjectOrg,
    ip_ssl_subject_cn:  ipSslSubjectCN,
    ip_ssl_san:         ipSslSANs,
    ip_jarm:            ipJarm,

    // Domain-level evidence
    nameservers:          nameservers,
    a_records:            aRecords,
    aaaa_records:         aaaaRecords,
    cdn_txt_tokens:       cdnTxtTokens,
    fastly_txt_records:   fastlyTxt,
    domain_ssl_subject:   domainSslSubjectOrg,
    domain_ssl_issuer:    domainSslIssuerOrg,
    domain_ssl_san:       domainSslSANs,
    domain_jarm:          domainJarm
  }
}];

