const expiryDateISO = expiryEvent?.event_date || null;
const expiryUnix    = expiryDateISO
  ? Math.floor(new Date(expiryDateISO).getTime() / 1000)
  : null;

const daysUntilExpiry = expiryUnix
  ? Math.floor((expiryUnix - NOW_UNIX) / 86400)
  : null;

const expiryStatus = daysUntilExpiry === null ? 'unknown'
  : daysUntilExpiry < 0   ? 'EXPIRED'
  : daysUntilExpiry < 30  ? 'CRITICAL'
  : daysUntilExpiry < 90  ? 'WARNING'
  : 'OK';

// ── 3. LAST UPDATE DATE ──────────────────────────────────────
const lastUpdateUnix = domainAttr?.last_update_date || null;
const lastUpdateISO  = lastUpdateUnix
  ? new Date(lastUpdateUnix * 1000).toISOString()
  : null;

// ── 4. RDAP REGISTRATION EVENT ───────────────────────────────
const registrationEvent = domainAttr?.rdap?.events?.find(e =>
  e.event_action === 'registration'
