// ── 6. REGISTRANT ────────────────────────────────────────────
const registrantEntity = domainAttr?.rdap?.entities?.find(e =>
  e.roles?.includes('registrant')
);
const registrantEmail   = registrantEntity?.vcard_array
  ?.find(v => v.name === 'email')?.values?.[0] || null;
const registrantCountry = registrantEntity?.vcard_array
  ?.find(v => v.name === 'adr')?.parameters?.cc?.[0] || null;
const registrantState   = registrantEntity?.vcard_array
  ?.find(v => v.name === 'adr')?.values?.[4] || null;

// ── 7. DOMAIN STATUS FLAGS ───────────────────────────────────
const domainStatusFlags = domainAttr?.rdap?.status || [];
const isLocked = domainStatusFlags.some(s =>
  s.includes('prohibited')
);
const lockTypes = domainStatusFlags.filter(s =>
  s.includes('prohibited')
);

// ── 8. DNSSEC ────────────────────────────────────────────────
const dnssecDelegationSigned = domainAttr?.rdap?.secure_dns?.delegation_signed ?? null;
const dnssecZoneSigned       = domainAttr?.rdap?.secure_dns?.zone_signed ?? null;

// ── 9. WHOIS PARSED ──────────────────────────────────────────
const whoisRaw = domainAttr?.whois || '';

const parseWhois = (field) => {
  const match = whoisRaw.match(new RegExp(`${field}:\\s*(.+)`));
  return match ? match[1].trim() : null;
};

const whoisCreateDate  = parseWhois('Create date');
const whoisExpiry      = parseWhois('Expiry date');
const whoisRegistrar   = parseWhois('Domain registrar url');
const whoisUpdated     = parseWhois('Update date');
const whoisDomainName  = parseWhois('Domain name');

// ── 10. TLD ──────────────────────────────────────────────────
const tld        = domainAttr?.tld || null;
const domainId   = domainData?.json.data.id || null;

// ── 11. LAST WHOIS DATE ──────────────────────────────────────
const whoisDateUnix = domainAttr?.whois_date || null;
const whoisDateISO  = whoisDateUnix
  ? new Date(whoisDateUnix * 1000).toISOString()
  : null;

// ── OUTPUT ───────────────────────────────────────────────────
return [{
  json: {
    _node: 'Domain Age and Registration Artifacts — VT',

    // Domain identity
    domain:    domainId,
    tld:       tld,

    // Age
    creation_date_iso:  creationDateISO,
    domain_age_years:   domainAgeYears,
    domain_age_days:    domainAgeDays,

    // Expiry
    expiry_date_iso:    expiryDateISO,
    days_until_expiry:  daysUntilExpiry,
    expiry_status:      expiryStatus,

    // Last update
    last_update_iso:    lastUpdateISO,

    // RDAP registration
    rdap_registration_date: rdapRegistrationDate,

    // Registrar
    registrar_name: registrarName,
    registrar_id:   registrarId,
    registrar_url:  whoisRegistrar,

    // Registrant
    registrant_email:   registrantEmail,
    registrant_country: registrantCountry,
    registrant_state:   registrantState,

    // Domain lock
    is_locked:    isLocked,
    lock_types:   lockTypes,
    status_flags: domainStatusFlags,

    // DNSSEC
    dnssec_delegation_signed: dnssecDelegationSigned,
    dnssec_zone_signed:       dnssecZoneSigned,

    // WHOIS
    whois_create_date: whoisCreateDate,
    whois_expiry:      whoisExpiry,
    whois_updated:     whoisUpdated,
    whois_domain_name: whoisDomainName,
    whois_date_iso:    whoisDateISO,
  }
}];

// ============================================================
// NODE: Domain & Reputation Assessment Artifacts — VT
// ============================================================

const domainData = $input.all().find(item => item.json.data?.type === 'domain');
const urlData    = $input.all().find(item => item.json.data?.type === 'url_analysis');
const domainAttr = domainData?.json.data.attributes;
const urlAttr    = urlData?.json.data.attributes;

// ── 1. DOMAIN ANALYSIS STATS ─────────────────────────────────
const domainStats      = domainAttr?.last_analysis_stats;
const domainEngines    = domainAttr?.last_analysis_results || {};
const totalEngines     = Object.keys(domainEngines).length;

const maliciousEngines  = Object.entries(domainEngines)
  .filter(([_,v]) => v.category === 'malicious').map(([k]) => k);
const suspiciousEngines = Object.entries(domainEngines)
  .filter(([_,v]) => v.category === 'suspicious').map(([k]) => k);
const harmlessEngines   = Object.entries(domainEngines)
  .filter(([_,v]) => v.category === 'harmless').map(([k]) => k);
const undetectedEngines = Object.entries(domainEngines)
  .filter(([_,v]) => v.category === 'undetected').map(([k]) => k);

// ── 2. URL ANALYSIS STATS (completed scan) ───────────────────
const urlStats         = urlAttr?.stats || null;
const urlScanStatus    = urlAttr?.status || null;
const urlScanDate      = urlAttr?.date
  ? new Date(urlAttr.date * 1000).toISOString()
  : null;
const urlScanned       = urlAttr?.url || urlData?.json.meta?.url_info?.url || null;

const urlMalicious     = urlStats?.malicious ?? null;
const urlSuspicious    = urlStats?.suspicious ?? null;
const urlHarmless      = urlStats?.harmless ?? null;
const urlUndetected    = urlStats?.undetected ?? null;

// ── 3. REPUTATION SCORE ──────────────────────────────────────
const reputationScore  = domainAttr?.reputation ?? null;
const communityVotes   = domainAttr?.total_votes || {};

// ── 4. HTTPS / SSL STATUS ────────────────────────────────────
const sslCert          = domainAttr?.last_https_certificate;
const httpsEnabled     = !!sslCert;
const sslValidFrom     = sslCert?.validity?.not_before || null;
const sslValidUntil    = sslCert?.validity?.not_after  || null;
const sslIssuer        = sslCert?.issuer?.O || null;
const sslSubjectOrg    = sslCert?.subject?.O || null;
const sslSubjectCN     = sslCert?.subject?.CN || null;
const sslKeyAlgo       = sslCert?.public_key?.algorithm || null;

const sslExpired = sslValidUntil
  ? new Date(sslValidUntil) < new Date()
  : null;

// ── 5. POPULARITY RANKS ──────────────────────────────────────
const popularityRanks  = domainAttr?.popularity_ranks || {};
const rankMajestic     = popularityRanks?.Majestic?.rank     ?? null;
const rankAlexa        = popularityRanks?.Alexa?.rank        ?? null;
const rankCisco        = popularityRanks?.['Cisco Umbrella']?.rank ?? null;
const rankQuantcast    = popularityRanks?.Quantcast?.rank    ?? null;
const rankCloudflare   = popularityRanks?.['Cloudflare Radar']?.rank ?? null;
const rankStatvoo      = popularityRanks?.Statvoo?.rank      ?? null;

const isPopular = (rankMajestic && rankMajestic < 10000) ||
                  (rankAlexa    && rankAlexa    < 10000) ||
                  (rankCisco    && rankCisco    < 10000);

// ── 6. CATEGORIES (content classification) ───────────────────
const categories       = domainAttr?.categories || {};
const categoryValues   = Object.values(categories);

// ── 7. CROWDSOURCED THREAT CONTEXT ───────────────────────────
const crowdsourced     = domainAttr?.crowdsourced_context || [];
const threatContexts   = crowdsourced.map(c => ({
  title:    c.title,
  source:   c.source,
  severity: c.severity,
  details:  c.details?.substring(0, 300)
}));

// ── 8. TAGS ──────────────────────────────────────────────────
const tags             = domainAttr?.tags || [];

// ── 9. LAST SCAN DATES ───────────────────────────────────────
const lastAnalysisDate = domainAttr?.last_analysis_date
  ? new Date(domainAttr.last_analysis_date * 1000).toISOString()
  : null;
const lastModifiedDate = domainAttr?.last_modification_date
  ? new Date(domainAttr.last_modification_date * 1000).toISOString()
  : null;
const lastDnsDate      = domainAttr?.last_dns_records_date
  ? new Date(domainAttr.last_dns_records_date * 1000).toISOString()
  : null;
const lastCertDate     = domainAttr?.last_https_certificate_date
  ? new Date(domainAttr.last_https_certificate_date * 1000).toISOString()
  : null;

// ── 10. PHISHING-SPECIFIC ENGINES ────────────────────────────
const PHISHING_ENGINES = ['Phishtank','OpenPhish','PhishFort','PhishLabs','Phishing Database'];
const phishingResults  = PHISHING_ENGINES.map(engine => ({
  engine,
  result: domainEngines[engine]?.category || 'not_checked'
}));
const phishingFlagged  = phishingResults.filter(p =>
  p.result === 'malicious' || p.result === 'suspicious'
);

// ── OUTPUT ───────────────────────────────────────────────────
return [{
  json: {
    _node: 'Domain & Reputation Assessment Artifacts — VT',

    // Domain identity
    domain: domainData?.json.data.id,
    url_scanned: urlScanned,

    // Domain engine stats
    domain_engines_total:      totalEngines,
    domain_engines_malicious:  domainStats?.malicious,
    domain_engines_suspicious: domainStats?.suspicious,
    domain_engines_harmless:   domainStats?.harmless,
    domain_engines_undetected: domainStats?.undetected,
    domain_malicious_engines:  maliciousEngines,
    domain_suspicious_engines: suspiciousEngines,
    domain_harmless_engines:   harmlessEngines,
    domain_undetected_engines: undetectedEngines,

    // URL scan stats
    url_scan_status:     urlScanStatus,
    url_scan_date:       urlScanDate,
    url_malicious:       urlMalicious,
    url_suspicious:      urlSuspicious,
    url_harmless:        urlHarmless,
    url_undetected:      urlUndetected,

    // Reputation
    reputation_score:  reputationScore,
    community_votes:   communityVotes,

    // HTTPS / SSL
    https_enabled:     httpsEnabled,
    ssl_valid_from:    sslValidFrom,
    ssl_valid_until:   sslValidUntil,
    ssl_expired:       sslExpired,
    ssl_issuer:        sslIssuer,
    ssl_subject_org:   sslSubjectOrg,
    ssl_subject_cn:    sslSubjectCN,
    ssl_key_algorithm: sslKeyAlgo,
    last_cert_date:    lastCertDate,

    // Popularity
    is_popular:         isPopular,
    rank_majestic:      rankMajestic,
    rank_alexa:         rankAlexa,
    rank_cisco_umbrella:rankCisco,
    rank_quantcast:     rankQuantcast,
    rank_cloudflare:    rankCloudflare,
    rank_statvoo:       rankStatvoo,

    // Categories
    categories:         categories,
    category_values:    categoryValues,

    // Phishing check
    phishing_engines_checked: phishingResults,
    phishing_flagged:         phishingFlagged,
    phishing_flag_count:      phishingFlagged.length,

    // Threat intel
    threat_contexts:    threatContexts,
    tags:               tags,

    // Timestamps
    last_analysis_date: lastAnalysisDate,
    last_modified_date: lastModifiedDate,
    last_dns_date:      lastDnsDate,
  }
}];

// ============================================================
// NODE: Domain Blacklist & Reputation Artifacts — VT
// ============================================================

const domainData = $input.all().find(item => item.json.data?.type === 'domain');
const urlData    = $input.all().find(item => item.json.data?.type === 'url_analysis');
const domainAttr = domainData?.json.data.attributes;
const urlAttr    = urlData?.json.data.attributes;

const domainEngines = domainAttr?.last_analysis_results || {};
const urlEngines    = urlAttr?.results || {};

// ── 1. FULL BLACKLIST VERDICT — DOMAIN ───────────────────────
const domainBlacklist = Object.entries(domainEngines).map(([name, v]) => ({
  engine:   name,
  category: v.category,
  result:   v.result,
  method:   v.method
}));

const domainMalicious  = domainBlacklist.filter(e => e.category === 'malicious');
const domainSuspicious = domainBlacklist.filter(e => e.category === 'suspicious');
const domainHarmless   = domainBlacklist.filter(e => e.category === 'harmless');
const domainUndetected = domainBlacklist.filter(e => e.category === 'undetected');

// ── 2. FULL BLACKLIST VERDICT — URL ──────────────────────────
const urlBlacklist = Object.entries(urlEngines).map(([name, v]) => ({
  engine:   name,
  category: v.category,
  result:   v.result,
  method:   v.method
}));

const urlMalicious  = urlBlacklist.filter(e => e.category === 'malicious');
const urlSuspicious = urlBlacklist.filter(e => e.category === 'suspicious');
const urlHarmless   = urlBlacklist.filter(e => e.category === 'harmless');
const urlUndetected = urlBlacklist.filter(e => e.category === 'undetected');

// ── 3. SPECIFIC BLACKLIST ENGINE GROUPS ──────────────────────
const PHISHING_ENGINES  = ['Phishtank','OpenPhish','PhishFort','PhishLabs','Phishing Database','Chong Lua Dao'];
const MALWARE_ENGINES   = ['MalwarePatrol','MalwareURL','Malwared','URLhaus','VX Vault','CRDF'];
const SPAM_ENGINES      = ['Spam404','StopForumSpam','Abusix','SCUMWARE.org'];
const THREAT_INTEL      = ['AlienVault','ArcSight Threat Intelligence','Kaspersky','Sophos','ESET','Fortinet','BitDefender'];
const SEARCH_ENGINES    = ['Google Safebrowsing','Yandex Safebrowsing'];

const checkEngineGroup = (group, engines) =>
  group.map(name => ({
    engine:   name,
    category: engines[name]?.category || 'not_checked',
    result:   engines[name]?.result   || 'not_checked'
  }));

// Domain checks per group
const phishingCheck   = checkEngineGroup(PHISHING_ENGINES,  domainEngines);
const malwareCheck    = checkEngineGroup(MALWARE_ENGINES,   domainEngines);
const spamCheck       = checkEngineGroup(SPAM_ENGINES,      domainEngines);
const threatIntelCheck= checkEngineGroup(THREAT_INTEL,      domainEngines);
const searchEngCheck  = checkEngineGroup(SEARCH_ENGINES,    domainEngines);

// Flagged per group
const phishingFlagged   = phishingCheck.filter(e   => e.category === 'malicious' || e.category === 'suspicious');
const malwareFlagged    = malwareCheck.filter(e    => e.category === 'malicious' || e.category === 'suspicious');
const spamFlagged       = spamCheck.filter(e       => e.category === 'malicious' || e.category === 'suspicious');
const threatIntelFlagged= threatIntelCheck.filter(e => e.category === 'malicious' || e.category === 'suspicious');
const searchEngFlagged  = searchEngCheck.filter(e  => e.category === 'malicious' || e.category === 'suspicious');

// ── 4. POPULARITY (typosquatting proxy) ──────────────────────
const popularityRanks = domainAttr?.popularity_ranks || {};
const rankSources     = Object.entries(popularityRanks).map(([source, data]) => ({
  source,
  rank:      data.rank,
  timestamp: new Date(data.timestamp * 1000).toISOString()
}));
const topRank = rankSources.reduce((min, r) =>
  r.rank < (min?.rank ?? Infinity) ? r : min, null
);

// ── 5. REPUTATION & VOTES ────────────────────────────────────
const reputationScore  = domainAttr?.reputation ?? null;
const communityVotes   = domainAttr?.total_votes || {};
const communityFlagged = (communityVotes?.malicious ?? 0) > 0;

// ── 6. CROWDSOURCED THREAT CONTEXT ───────────────────────────
const crowdsourced   = domainAttr?.crowdsourced_context || [];
const threatSeverity = crowdsourced.map(c => ({
  title:    c.title,
  severity: c.severity,
  source:   c.source
}));
const highSeverityThreats = threatSeverity.filter(t =>
  t.severity === 'high' || t.severity === 'critical'
);

// ── 7. TAGS ──────────────────────────────────────────────────
const tags = domainAttr?.tags || [];

// ── 8. CATEGORIES ────────────────────────────────────────────
const categories     = domainAttr?.categories || {};
const SUSPECT_CATS   = ['malware','phishing','spam','botnet','exploit','fraud','gambling'];
const suspectCats    = Object.entries(categories).filter(([_, v]) =>
  SUSPECT_CATS.some(s => v.toLowerCase().includes(s))
);

// ── 9. SUMMARY COUNTS ────────────────────────────────────────
const domainTotalEngines = Object.keys(domainEngines).length;
const urlTotalEngines    = Object.keys(urlEngines).length;

// ── OUTPUT ───────────────────────────────────────────────────
return [{
  json: {
    _node: 'Domain Blacklist & Reputation Artifacts — VT',

    // Domain identity
    domain:      domainData?.json.data.id,
    url_scanned: urlAttr?.url || null,

    // ── Domain blacklist summary
    domain_total_engines:     domainTotalEngines,
    domain_malicious_count:   domainMalicious.length,
    domain_suspicious_count:  domainSuspicious.length,
    domain_harmless_count:    domainHarmless.length,
    domain_undetected_count:  domainUndetected.length,
    domain_malicious_engines: domainMalicious,
    domain_suspicious_engines:domainSuspicious,

    // ── URL blacklist summary
    url_total_engines:        urlTotalEngines,
    url_malicious_count:      urlMalicious.length,
    url_suspicious_count:     urlSuspicious.length,
    url_harmless_count:       urlHarmless.length,
    url_undetected_count:     urlUndetected.length,
    url_malicious_engines:    urlMalicious,
    url_suspicious_engines:   urlSuspicious,

    // ── Engine group checks
    phishing_engines:         phishingCheck,
    phishing_flagged:         phishingFlagged,
    phishing_flag_count:      phishingFlagged.length,

    malware_engines:          malwareCheck,
    malware_flagged:          malwareFlagged,
    malware_flag_count:       malwareFlagged.length,

    spam_engines:             spamCheck,
    spam_flagged:             spamFlagged,
    spam_flag_count:          spamFlagged.length,

    threat_intel_engines:     threatIntelCheck,
    threat_intel_flagged:     threatIntelFlagged,
    threat_intel_flag_count:  threatIntelFlagged.length,

    search_engine_check:      searchEngCheck,
    search_engine_flagged:    searchEngFlagged,

    // ── Reputation
    reputation_score:         reputationScore,
    community_votes:          communityVotes,
    community_flagged:        communityFlagged,

    // ── Popularity (anti-typosquatting signal)
    popularity_ranks:         rankSources,
    top_rank:                 topRank,
    is_popular:               topRank ? topRank.rank < 10000 : false,

    // ── Threat intel context
    threat_contexts:          threatSeverity,
    high_severity_threats:    highSeverityThreats,

    // ── Categories
    categories:               categories,
    suspect_categories:       suspectCats,

    // ── Tags
    tags
  }
}];

// ============================================================
// NODE: DNS Hygiene and Configuration Artifacts — VT
// ============================================================

const domainData = $input.all().find(item => item.json.data?.type === 'domain');
const domainAttr = domainData?.json.data.attributes;

const dnsRecords = domainAttr?.last_dns_records || [];

// ── HELPER: filter by type ────────────────────────────────────
const byType = (type) => dnsRecords.filter(r => r.type === type);

// ── 1. A RECORDS ─────────────────────────────────────────────
const aRecords    = byType('A').map(r => ({ value: r.value, ttl: r.ttl }));
const aaaaRecords = byType('AAAA').map(r => ({ value: r.value, ttl: r.ttl }));
const hasA        = aRecords.length > 0;
const hasAAAA     = aaaaRecords.length > 0;

// ── 2. NS RECORDS ─────────────────────────────────────────────
const nsRecords = byType('NS').map(r => ({ value: r.value, ttl: r.ttl }));
const hasNS     = nsRecords.length > 0;
const nsCount   = nsRecords.length;

// ── 3. MX RECORDS ─────────────────────────────────────────────
const mxRecords = byType('MX').map(r => ({
  value:    r.value,
  priority: r.priority,
  ttl:      r.ttl
}));
const hasMX   = mxRecords.length > 0;
const mxCount = mxRecords.length;

// ── 4. SOA RECORD ─────────────────────────────────────────────
const soaRecord = byType('SOA')[0] || null;
const hasSOA    = !!soaRecord;
const soaDetails = soaRecord ? {
  primary_ns: soaRecord.value,
  rname:      soaRecord.rname,
  serial:     soaRecord.serial,
  refresh:    soaRecord.refresh,
  retry:      soaRecord.retry,
  expire:     soaRecord.expire,
  minimum:    soaRecord.minimum,
  ttl:        soaRecord.ttl
} : null;

// ── 5. TXT RECORDS ────────────────────────────────────────────
const txtRecords    = byType('TXT').map(r => r.value);
const txtCount      = txtRecords.length;

// ── 6. SPF ────────────────────────────────────────────────────
const spfRecord     = txtRecords.find(t => t.startsWith('v=spf1'));
const hasSPF        = !!spfRecord;
const spfPolicy     = spfRecord
  ? spfRecord.includes('-all') ? 'hard_fail'
  : spfRecord.includes('~all') ? 'soft_fail'
  : spfRecord.includes('?all') ? 'neutral'
  : spfRecord.includes('+all') ? 'pass_all_DANGEROUS'
  : 'unknown'
  : null;
const spfIncludes   = spfRecord
  ? [...spfRecord.matchAll(/include:([^\s]+)/g)].map(m => m[1])
  : [];
const spfExists     = spfRecord
  ? [...spfRecord.matchAll(/exists:([^\s]+)/g)].map(m => m[1])
  : [];

// ── 7. DMARC ──────────────────────────────────────────────────
const dmarcRecord   = txtRecords.find(t => t.startsWith('v=DMARC1'));
const hasDMARC      = !!dmarcRecord;
const dmarcPolicy   = dmarcRecord
  ? (dmarcRecord.match(/p=([^;]+)/) || [])[1] || 'unknown'
  : null;
const dmarcRua      = dmarcRecord
  ? (dmarcRecord.match(/rua=([^;]+)/) || [])[1] || null
  : null;
const dmarcRuf      = dmarcRecord
  ? (dmarcRecord.match(/ruf=([^;]+)/) || [])[1] || null
  : null;
const dmarcPct      = dmarcRecord
  ? parseInt((dmarcRecord.match(/pct=([^;]+)/) || [])[1]) || 100
  : null;

// ── 8. DKIM (selector tokens in TXT) ─────────────────────────
// VT does not return _domainkey subdomains directly
// but we can detect any dkim-related TXT hints
const dkimHints     = txtRecords.filter(t =>
  t.toLowerCase().includes('dkim') ||
  t.toLowerCase().includes('domainkey')
);
const hasDkimHints  = dkimHints.length > 0;

// ── 9. CAA RECORDS ────────────────────────────────────────────
const caaRecords    = byType('CAA') || [];
const hasCAA        = caaRecords.length > 0;

// ── 10. DNSSEC ────────────────────────────────────────────────
const dnssecSigned  = domainAttr?.rdap?.secure_dns?.delegation_signed ?? false;
const zoneSign      = domainAttr?.rdap?.secure_dns?.zone_signed ?? false;
const dsData        = domainAttr?.rdap?.secure_dns?.ds_data || [];
const keyData       = domainAttr?.rdap?.secure_dns?.key_data || [];

// ── 11. NAMESERVERS FROM RDAP ────────────────────────────────
const rdapNameservers = domainAttr?.rdap?.nameservers
  ?.map(ns => ns.ldh_name) || [];

// ── 12. DNS RECORD DATE ──────────────────────────────────────
const dnsRecordsDate = domainAttr?.last_dns_records_date
  ? new Date(domainAttr.last_dns_records_date * 1000).toISOString()
  : null;

// ── 13. THIRD PARTY VERIFICATIONS IN TXT ─────────────────────
// Shows which services have verified this domain
const VERIFICATION_PATTERNS = [
  { name: 'google',      pattern: 'google-site-verification' },
  { name: 'facebook',    pattern: 'facebook-domain-verification' },
  { name: 'atlassian',   pattern: 'atlassian-domain-verification' },
  { name: 'stripe',      pattern: 'stripe-verification' },
  { name: 'adobe_sign',  pattern: 'adobe-sign-verification' },
  { name: 'openai',      pattern: 'openai-domain-verification' },
  { name: 'github',      pattern: '_github-challenge' },
  { name: 'fastly',      pattern: 'fastly-domain' },
  { name: 'zapier',      pattern: 'zapier-domain-verification' },
  { name: 'docker',      pattern: 'docker-verification' },
  { name: 'mongodb',     pattern: 'mongodb-site-verification' },
  { name: 'postman',     pattern: 'postman-domain-verification' },
  { name: 'anthropic',   pattern: 'anthropic-domain-verification' },
  { name: 'elevenlabs',  pattern: 'elevenlabs' },
  { name: 'miro',        pattern: 'miro-verification' },
];

const verifiedServices = VERIFICATION_PATTERNS
  .filter(({ pattern }) => txtRecords.some(t => t.includes(pattern)))
  .map(({ name }) => name);

// ── 14. ALL RECORD TYPE SUMMARY ──────────────────────────────
const recordTypeSummary = dnsRecords.reduce((acc, r) => {
  acc[r.type] = (acc[r.type] || 0) + 1;
  return acc;
}, {});

// ── OUTPUT ───────────────────────────────────────────────────
return [{
  json: {
    _node: 'DNS Hygiene and Configuration Artifacts — VT',

    domain:           domainData?.json.data.id,
    dns_records_date: dnsRecordsDate,
    total_records:    dnsRecords.length,
    record_type_summary: recordTypeSummary,

    // ── A / AAAA
    has_a_record:     hasA,
    has_aaaa_record:  hasAAAA,
    a_records:        aRecords,
    aaaa_records:     aaaaRecords,

    // ── NS
    has_ns_record:    hasNS,
    ns_count:         nsCount,
    ns_records:       nsRecords,
    rdap_nameservers: rdapNameservers,

    // ── MX
    has_mx_record:    hasMX,
    mx_count:         mxCount,
    mx_records:       mxRecords,

    // ── SOA
    has_soa_record:   hasSOA,
    soa:              soaDetails,

    // ── TXT
    txt_count:        txtCount,
    txt_records:      txtRecords,

    // ── SPF
    has_spf:          hasSPF,
    spf_record:       spfRecord || null,
    spf_policy:       spfPolicy,
    spf_includes:     spfIncludes,
    spf_exists:       spfExists,

    // ── DMARC
    has_dmarc:        hasDMARC,
    dmarc_record:     dmarcRecord || null,
    dmarc_policy:     dmarcPolicy,
    dmarc_rua:        dmarcRua,
    dmarc_ruf:        dmarcRuf,
    dmarc_pct:        dmarcPct,

    // ── DKIM
    dkim_hints_found: hasDkimHints,
    dkim_hints:       dkimHints,

    // ── CAA
    has_caa_record:   hasCAA,
    caa_records:      caaRecords,

    // ── DNSSEC
    dnssec_delegation_signed: dnssecSigned,
    dnssec_zone_signed:       zoneSign,
    dnssec_ds_data:           dsData,
    dnssec_key_data:          keyData,

    // ── Third party verifications
    verified_services:        verifiedServices,
    verified_service_count:   verifiedServices.length,
  }
}];

// ============================================================
// NODE: Email Security – SPF Artifacts — VT
// ============================================================

const domainData = $input.all().find(item => item.json.data?.type === 'domain');
const domainAttr = domainData?.json.data.attributes;

const txtRecords = (domainAttr?.last_dns_records || [])
  .filter(r => r.type === 'TXT')
  .map(r => r.value);

const mxRecords = (domainAttr?.last_dns_records || [])
  .filter(r => r.type === 'MX')
  .map(r => ({ value: r.value, priority: r.priority, ttl: r.ttl }));

// ── 1. SPF RECORD DETECTION ───────────────────────────────────
const spfRecord  = txtRecords.find(t => t.startsWith('v=spf1')) || null;
const hasSPF     = !!spfRecord;

// ── 2. MULTIPLE SPF CHECK (RFC violation if >1) ───────────────
const allSpfRecords = txtRecords.filter(t => t.startsWith('v=spf1'));
const multipleSpf   = allSpfRecords.length > 1;

// ── 3. POLICY (ALL MECHANISM) ────────────────────────────────
const spfPolicy = !spfRecord ? 'missing'
  : spfRecord.includes('-all') ? 'hard_fail'
  : spfRecord.includes('~all') ? 'soft_fail'
  : spfRecord.includes('?all') ? 'neutral'
  : spfRecord.includes('+all') ? 'pass_all_DANGEROUS'
  : 'no_all_mechanism';

const spfPolicyRating = {
  'hard_fail':          'PASS',
  'soft_fail':          'WARN',
  'neutral':            'WARN',
  'pass_all_DANGEROUS': 'FAIL',
  'no_all_mechanism':   'FAIL',
  'missing':            'FAIL'
}[spfPolicy] || 'UNKNOWN';

// ── 4. MECHANISMS PARSED ─────────────────────────────────────
const spfIncludes  = spfRecord
  ? [...spfRecord.matchAll(/include:([^\s]+)/g)].map(m => m[1])
  : [];

const spfExists    = spfRecord
  ? [...spfRecord.matchAll(/exists:([^\s]+)/g)].map(m => m[1])
  : [];

const spfIp4       = spfRecord
  ? [...spfRecord.matchAll(/ip4:([^\s]+)/g)].map(m => m[1])
  : [];

const spfIp6       = spfRecord
  ? [...spfRecord.matchAll(/ip6:([^\s]+)/g)].map(m => m[1])
  : [];

const spfRedirect  = spfRecord
  ? (spfRecord.match(/redirect=([^\s]+)/) || [])[1] || null
  : null;

const spfA         = spfRecord
  ? [...spfRecord.matchAll(/\ba:([^\s]+)/g)].map(m => m[1])
  : [];

const spfMx        = spfRecord
  ? /\bmx\b/.test(spfRecord)
  : false;

const spfPtr       = spfRecord
  ? /\bptr\b/.test(spfRecord)
  : false;  // ptr is deprecated / bad practice

// ── 5. DNS LOOKUP COUNT ESTIMATE ─────────────────────────────
// RFC 7208: max 10 DNS lookups. Each include/exists/a/mx = 1 lookup
const estimatedLookups =
  spfIncludes.length +
  spfExists.length   +
  spfA.length        +
  (spfMx ? 1 : 0)   +
  (spfRedirect ? 1 : 0);

const lookupLimitExceeded = estimatedLookups > 10;

// ── 6. KNOWN EMAIL PROVIDERS IN SPF ──────────────────────────
const EMAIL_PROVIDERS = [
  { name: 'Microsoft 365 / Exchange Online', pattern: 'protection.outlook.com' },
  { name: 'Google Workspace',                pattern: '_spf.google.com' },
  { name: 'Agari (anti-phishing)',            pattern: 'agari.com' },
  { name: 'Intacct',                          pattern: '_spf.intacct.com' },
  { name: 'Mandrill / Mailchimp',             pattern: 'mandrill' },
  { name: 'SendGrid',                         pattern: 'sendgrid.net' },
  { name: 'Amazon SES',                       pattern: 'amazonses.com' },
  { name: 'Salesforce',                       pattern: 'salesforce.com' },
  { name: 'Mailgun',                          pattern: 'mailgun.org' },
  { name: 'Postmark',                         pattern: 'spf.mtasv.net' },
];

const detectedProviders = EMAIL_PROVIDERS.filter(p =>
  spfRecord && spfRecord.includes(p.pattern)
).map(p => p.name);

// ── 7. MX PROVIDERS (who receives email) ─────────────────────
const MX_PROVIDERS = [
  { name: 'Microsoft 365', pattern: 'protection.outlook.com' },
  { name: 'Google Workspace', pattern: 'aspmx.l.google.com' },
  { name: 'Proofpoint',    pattern: 'pphosted.com' },
  { name: 'Mimecast',      pattern: 'mimecast.com' },
];

const mxProviders = MX_PROVIDERS.filter(p =>
  mxRecords.some(mx => mx.value.includes(p.pattern))
).map(p => p.name);

const mxValues = mxRecords.map(mx => mx.value);

// ── 8. ALIGNMENT CHECK (SPF includes match MX provider) ──────
// Best practice: SPF authorized senders should include MX hosts
const mxInSpf = mxValues.some(mx =>
  spfMx || spfIncludes.some(inc => mx.includes(inc.split('.').slice(-2).join('.')))
);

// ── 9. SPF ISSUES SUMMARY ────────────────────────────────────
const issues = [];
if (!hasSPF)                issues.push('SPF record missing');
if (multipleSpf)            issues.push('Multiple SPF records (RFC violation)');
if (spfPolicy === 'pass_all_DANGEROUS') issues.push('+all allows any server to send — critical');
if (spfPolicy === 'neutral') issues.push('?all policy too permissive');
if (spfPolicy === 'soft_fail') issues.push('~all soft fail — consider upgrading to -all');
if (spfPolicy === 'no_all_mechanism') issues.push('No -all/~all terminator — incomplete SPF');
if (lookupLimitExceeded)    issues.push(`DNS lookup limit exceeded (~${estimatedLookups} lookups, max 10)`);
if (spfPtr)                 issues.push('ptr mechanism used — deprecated and unreliable');
if (!mxInSpf && hasSPF)    issues.push('MX hosts may not be covered by SPF includes');

// ── OUTPUT ───────────────────────────────────────────────────
return [{
  json: {
    _node: 'Email Security – SPF Artifacts — VT',

    domain:      domainData?.json.data.id,

    // ── SPF presence
    has_spf:          hasSPF,
    spf_record:       spfRecord,
    all_spf_records:  allSpfRecords,
    multiple_spf:     multipleSpf,

    // ── Policy
    spf_policy:        spfPolicy,
    spf_policy_rating: spfPolicyRating,

    // ── Mechanisms
    spf_includes:     spfIncludes,
    spf_exists:       spfExists,
    spf_ip4:          spfIp4,
    spf_ip6:          spfIp6,
    spf_a:            spfA,
    spf_mx:           spfMx,
    spf_ptr:          spfPtr,
    spf_redirect:     spfRedirect,

    // ── DNS lookup estimate
    estimated_dns_lookups:  estimatedLookups,
    lookup_limit_exceeded:  lookupLimitExceeded,

    // ── Providers
    spf_email_providers:  detectedProviders,
    mx_records:           mxRecords,
    mx_providers:         mxProviders,
    mx_in_spf:            mxInSpf,

    // ── Issues
    issues:       issues,
    issue_count:  issues.length,
  }
}];

// ============================================================
// NODE: Email Security – DMARC Artifacts — VT
// ============================================================

const domainData = $input.all().find(item => item.json.data?.type === 'domain');
const domainAttr = domainData?.json.data.attributes;

const txtRecords = (domainAttr?.last_dns_records || [])
  .filter(r => r.type === 'TXT')
  .map(r => r.value);

const mxRecords = (domainAttr?.last_dns_records || [])
  .filter(r => r.type === 'MX')
  .map(r => ({ value: r.value, priority: r.priority }));

// ── 1. DMARC RECORD DETECTION ────────────────────────────────
const dmarcRecord  = txtRecords.find(t => t.startsWith('v=DMARC1')) || null;
const hasDMARC     = !!dmarcRecord;

// ── 2. MULTIPLE DMARC CHECK (RFC violation if >1) ────────────
const allDmarcRecords = txtRecords.filter(t => t.startsWith('v=DMARC1'));
const multipleDmarc   = allDmarcRecords.length > 1;

// ── 3. DMARC POLICY (p=) ─────────────────────────────────────
const dmarcPolicy = !dmarcRecord ? 'missing'
  : (dmarcRecord.match(/(?:^|;)\s*p=([^;]+)/) || [])[1]?.trim() || 'missing';

const dmarcPolicyRating = {
  'reject':     'PASS',
  'quarantine': 'WARN',
  'none':       'FAIL',
  'missing':    'FAIL'
}[dmarcPolicy] || 'UNKNOWN';

// ── 4. SUBDOMAIN POLICY (sp=) ────────────────────────────────
const dmarcSubPolicy = dmarcRecord
  ? (dmarcRecord.match(/(?:^|;)\s*sp=([^;]+)/) || [])[1]?.trim() || null
  : null;

const dmarcSubPolicyRating = !dmarcSubPolicy ? 'inherits_p'
  : dmarcSubPolicy === 'reject'     ? 'PASS'
  : dmarcSubPolicy === 'quarantine' ? 'WARN'
  : dmarcSubPolicy === 'none'       ? 'FAIL'
  : 'UNKNOWN';

// ── 5. PERCENTAGE (pct=) ─────────────────────────────────────
const dmarcPct = dmarcRecord
  ? parseInt((dmarcRecord.match(/(?:^|;)\s*pct=([^;]+)/) || [])[1]) || 100
  : null;

const pctRating = !dmarcPct       ? 'missing'
  : dmarcPct === 100              ? 'PASS'
  : dmarcPct >= 50                ? 'WARN'
  : 'FAIL';

// ── 6. REPORTING ADDRESSES ───────────────────────────────────
const dmarcRua = dmarcRecord
  ? (dmarcRecord.match(/(?:^|;)\s*rua=([^;]+)/) || [])[1]?.trim() || null
  : null;

const dmarcRuf = dmarcRecord
  ? (dmarcRecord.match(/(?:^|;)\s*ruf=([^;]+)/) || [])[1]?.trim() || null
  : null;

const ruaAddresses = dmarcRua
  ? dmarcRua.split(',').map(a => a.trim().replace('mailto:', ''))
  : [];

const rufAddresses = dmarcRuf
  ? dmarcRuf.split(',').map(a => a.trim().replace('mailto:', ''))
  : [];

// ── 7. ALIGNMENT MODES ───────────────────────────────────────
// adkim: DKIM alignment  aspf: SPF alignment
// r = relaxed (default), s = strict
const adkim = dmarcRecord
  ? (dmarcRecord.match(/(?:^|;)\s*adkim=([^;]+)/) || [])[1]?.trim() || 'relaxed'
  : null;

const aspf = dmarcRecord
  ? (dmarcRecord.match(/(?:^|;)\s*aspf=([^;]+)/) || [])[1]?.trim() || 'relaxed'
  : null;

// ── 8. FAILURE REPORTING OPTIONS (fo=) ───────────────────────
const fo = dmarcRecord
  ? (dmarcRecord.match(/(?:^|;)\s*fo=([^;]+)/) || [])[1]?.trim() || '0'
  : null;

const foMeaning = {
  '0': 'report if all mechanisms fail (default)',
  '1': 'report if any mechanism fails',
  'd': 'report DKIM failures',
  's': 'report SPF failures'
}[fo] || fo;

// ── 9. REPORT FORMAT (rf=) ───────────────────────────────────
const rf = dmarcRecord
  ? (dmarcRecord.match(/(?:^|;)\s*rf=([^;]+)/) || [])[1]?.trim() || 'afrf'
  : null;

// ── 10. REPORT INTERVAL (ri=) ────────────────────────────────
const ri = dmarcRecord
  ? parseInt((dmarcRecord.match(/(?:^|;)\s*ri=([^;]+)/) || [])[1]) || 86400
  : null;

const riHours = ri ? Math.round(ri / 3600) : null;

// ── 11. SPF PRESENCE CROSS-CHECK ─────────────────────────────
const spfRecord = txtRecords.find(t => t.startsWith('v=spf1')) || null;
const hasSPF    = !!spfRecord;

// ── 12. DMARC MATURITY LEVEL ─────────────────────────────────
// none = monitoring, quarantine = partial, reject = enforced
const maturityLevel =
  !hasDMARC                    ? 'NOT_CONFIGURED' :
  dmarcPolicy === 'none'       ? 'MONITORING' :
  dmarcPolicy === 'quarantine' ? 'PARTIAL_ENFORCEMENT' :
  dmarcPolicy === 'reject'     ? 'FULL_ENFORCEMENT' :
  'UNKNOWN';

// ── 13. ISSUES SUMMARY ───────────────────────────────────────
const issues = [];
if (!hasDMARC)                        issues.push('DMARC record missing');
if (multipleDmarc)                    issues.push('Multiple DMARC records (RFC violation)');
if (dmarcPolicy === 'none')           issues.push('p=none — monitoring only, no enforcement');
if (dmarcPolicy === 'quarantine')     issues.push('p=quarantine — not fully enforced, upgrade to reject');
if (dmarcPct !== null && dmarcPct < 100) issues.push(`pct=${dmarcPct} — policy applied to only ${dmarcPct}% of emails`);
if (!dmarcRua)                        issues.push('No rua reporting address — aggregate reports disabled');
if (!dmarcRuf)                        issues.push('No ruf forensic reporting address (optional but useful)');
if (dmarcSubPolicy === 'none')        issues.push('sp=none — subdomains not protected');
if (hasDMARC && !hasSPF)             issues.push('DMARC present but SPF missing — DMARC alignment will fail');
if (adkim === 'relaxed' && aspf === 'relaxed') issues.push('Both alignments relaxed — consider strict for critical domains');

// ── OUTPUT ───────────────────────────────────────────────────
return [{
  json: {
    _node: 'Email Security – DMARC Artifacts — VT',

    domain:      domainData?.json.data.id,

    // ── DMARC presence
    has_dmarc:          hasDMARC,
    dmarc_record:       dmarcRecord,
    all_dmarc_records:  allDmarcRecords,
    multiple_dmarc:     multipleDmarc,

    // ── Policy
    dmarc_policy:        dmarcPolicy,
    dmarc_policy_rating: dmarcPolicyRating,
    maturity_level:      maturityLevel,

    // ── Subdomain policy
    dmarc_sub_policy:        dmarcSubPolicy,
    dmarc_sub_policy_rating: dmarcSubPolicyRating,

    // ── Percentage
    dmarc_pct:        dmarcPct,
    pct_rating:       pctRating,

    // ── Reporting
    rua:              dmarcRua,
    ruf:              dmarcRuf,
    rua_addresses:    ruaAddresses,
    ruf_addresses:    rufAddresses,

    // ── Alignment
    adkim:            adkim,
    aspf:             aspf,

    // ── Failure reporting
    fo:               fo,
    fo_meaning:       foMeaning,
    rf:               rf,
    ri_seconds:       ri,
    ri_hours:         riHours,

    // ── Cross-checks
    has_spf:          hasSPF,
    spf_record:       spfRecord,
    mx_records:       mxRecords,

    // ── Issues
    issues:           issues,
    issue_count:      issues.length,
  }
}];

// ============================================================
// NODE: WHOIS Transparency Artifacts — VT
// ============================================================

const domainData = $input.all().find(item => item.json.data?.type === 'domain');
const domainAttr = domainData?.json.data.attributes;

const whoisRaw  = domainAttr?.whois || '';
const rdap      = domainAttr?.rdap  || {};

// ── HELPER: parse whois key-value ────────────────────────────
const parseWhois = (field) => {
  const match = whoisRaw.match(new RegExp(`${field}:\\s*(.+)`, 'i'));
  return match ? match[1].trim() : null;
};

// ── 1. WHOIS RAW AVAILABILITY ────────────────────────────────
const hasWhois     = whoisRaw.length > 0;
const whoisDateISO = domainAttr?.whois_date
  ? new Date(domainAttr.whois_date * 1000).toISOString()
  : null;

// ── 2. WHOIS PARSED FIELDS ───────────────────────────────────
const whoisDomain     = parseWhois('Domain name');
const whoisCreateDate = parseWhois('Create date');
const whoisExpiry     = parseWhois('Expiry date');
const whoisUpdated    = parseWhois('Update date');
const whoisRegistrar  = parseWhois('Domain registrar url');
const whoisRegId      = parseWhois('Domain registrar id');

// Registrant fields
const whoisRegName    = parseWhois('Registrant name');
const whoisRegCompany = parseWhois('Registrant company');
const whoisRegEmail   = parseWhois('Registrant email');
const whoisRegPhone   = parseWhois('Registrant phone');
const whoisRegAddress = parseWhois('Registrant address');
const whoisRegCity    = parseWhois('Registrant city');
const whoisRegState   = parseWhois('Registrant state');
const whoisRegZip     = parseWhois('Registrant zip');
const whoisRegCountry = parseWhois('Registrant country');

// Admin fields
const whoisAdminCity    = parseWhois('Administrative city');
const whoisAdminCountry = parseWhois('Administrative country');
const whoisAdminEmail   = parseWhois('Administrative email');
const whoisAdminState   = parseWhois('Administrative state');

// Technical fields
const whoisTechCity    = parseWhois('Technical city');
const whoisTechCountry = parseWhois('Technical country');
const whoisTechEmail   = parseWhois('Technical email');
const whoisTechState   = parseWhois('Technical state');

// ── 3. REDACTION DETECTION ───────────────────────────────────
// Redacted fields appear as hashed/encoded strings
const REDACTION_PATTERNS = [
  /^[a-f0-9]{16}$/i,           // 16-char hex hash
  /^[a-f0-9]{32}$/i,           // 32-char hex hash
  /anonymised\.email$/i,        // anonymised email domain
  /^redacted/i,                 // explicit redacted label
  /^\[.*redacted.*\]$/i,        // [REDACTED]
  /privacy/i,                   // privacy protection service
  /^data expunged/i,            // data expunged
];

const isRedacted = (value) => {
  if (!value) return null; // null = not present, different from redacted
  return REDACTION_PATTERNS.some(p => p.test(value.trim()));
};

const redactedFields = {
  registrant_name:    isRedacted(whoisRegName),
  registrant_company: isRedacted(whoisRegCompany),
  registrant_email:   isRedacted(whoisRegEmail),
  registrant_phone:   isRedacted(whoisRegPhone),
  registrant_address: isRedacted(whoisRegAddress),
  registrant_city:    isRedacted(whoisRegCity),
  registrant_state:   isRedacted(whoisRegState),
  registrant_zip:     isRedacted(whoisRegZip),
};

const redactedCount  = Object.values(redactedFields).filter(v => v === true).length;
const totalFields    = Object.keys(redactedFields).length;
const isFullyRedacted = redactedCount === totalFields;
const isPartiallyRedacted = redactedCount > 0 && !isFullyRedacted;

// ── 4. PRIVACY PROXY DETECTION ───────────────────────────────
const PRIVACY_SERVICES = [
  'anonymised.email', 'domainsbyproxy', 'whoisguard',
  'privacyprotect', 'contactprivacy', 'withheldforprivacy',
  'redacted for privacy', 'identity protect', 'perfect privacy',
  'privacy hero', 'networksolutions', 'registrar-specific'
];

const privacyDetected = PRIVACY_SERVICES.some(p =>
  whoisRaw.toLowerCase().includes(p)
) || (whoisRegEmail || '').includes('anonymised.email');

// ── 5. RDAP ENTITY TRANSPARENCY ──────────────────────────────
const rdapEntities   = rdap?.entities || [];

const rdapRegistrar  = rdapEntities.find(e => e.roles?.includes('registrar'));
const rdapRegistrant = rdapEntities.find(e => e.roles?.includes('registrant'));
const rdapTechnical  = rdapEntities.find(e => e.roles?.includes('technical'));
const rdapAbuse      = rdapEntities
  .flatMap(e => e.entities || [])
  .find(e => e.roles?.includes('abuse'));

const rdapRegistrarName = rdapRegistrar?.vcard_array
  ?.find(v => v.name === 'fn')?.values?.[0] || null;

const rdapRegistrantEmail = rdapRegistrant?.vcard_array
  ?.find(v => v.name === 'email')?.values?.[0] || null;

const rdapRegistrantCountry = rdapRegistrant?.vcard_array
  ?.find(v => v.name === 'adr')?.parameters?.cc?.[0] || null;

const rdapAbuseEmail = rdapAbuse?.vcard_array
  ?.find(v => v.name === 'email')?.values?.[0] || null;

const rdapAbusePhone = rdapAbuse?.vcard_array
  ?.find(v => v.name === 'tel')?.values?.[0] || null;

// ── 6. RDAP CONFORMANCE ──────────────────────────────────────
const rdapConformance   = rdap?.rdap_conformance || [];
const hasRdapConformance = rdapConformance.length > 0;
const icannCompliant    = rdapConformance.includes('icann_rdap_response_profile_1');
const rdapRedacted      = rdapConformance.includes('redacted');

// ── 7. DOMAIN STATUS FLAGS (EPP) ─────────────────────────────
const domainStatus      = rdap?.status || [];
const hasClientLock     = domainStatus.some(s => s.includes('client') && s.includes('prohibited'));
const hasServerLock     = domainStatus.some(s => s.includes('server') && s.includes('prohibited'));
const lockLevel =
  hasClientLock && hasServerLock ? 'full_lock'
  : hasServerLock                ? 'server_lock_only'
  : hasClientLock                ? 'client_lock_only'
  : 'unlocked';

// ── 8. DNSSEC ────────────────────────────────────────────────
const dnssecSigned = rdap?.secure_dns?.delegation_signed ?? false;
const zoneSigned   = rdap?.secure_dns?.zone_signed       ?? false;

// ── 9. REGISTRAR INFO ────────────────────────────────────────
const registrarId  = rdapRegistrar?.public_ids?.[0]?.identifier || whoisRegId || null;
const registrarUrl = parseWhois('Domain registrar url');

// ── 10. TRANSPARENCY SCORE ───────────────────────────────────
// Score out of 10 based on what is publicly available
let transparencyScore = 0;
if (hasWhois)                                   transparencyScore += 1;
if (whoisCreateDate)                            transparencyScore += 1;
if (whoisExpiry)                                transparencyScore += 1;
if (rdapRegistrarName)                          transparencyScore += 1;
if (rdapRegistrantCountry)                      transparencyScore += 1;
if (rdapAbuseEmail)                             transparencyScore += 1;
if (hasRdapConformance)                         transparencyScore += 1;
if (icannCompliant)                             transparencyScore += 1;
if (lockLevel === 'full_lock')                  transparencyScore += 1;
if (!privacyDetected || rdapAbuseEmail)         transparencyScore += 1;

const transparencyRating =
  transparencyScore >= 8 ? 'HIGH'
  : transparencyScore >= 5 ? 'MEDIUM'
  : 'LOW';

// ── 11. ISSUES ───────────────────────────────────────────────
const issues = [];
if (!hasWhois)           issues.push('WHOIS data unavailable');
if (isFullyRedacted)     issues.push('All registrant fields redacted — no ownership transparency');
if (privacyDetected)     issues.push('Privacy proxy / anonymisation service detected');
if (!rdapAbuseEmail)     issues.push('No abuse contact email in RDAP');
if (!icannCompliant)     issues.push('RDAP not ICANN compliant');
if (lockLevel === 'unlocked') issues.push('Domain has no EPP lock — transfer risk');
if (!dnssecSigned)       issues.push('DNSSEC not signed');
if (rdapRedacted)        issues.push('RDAP conformance includes "redacted" profile');

// ── OUTPUT ───────────────────────────────────────────────────
return [{
  json: {
    _node: 'WHOIS Transparency Artifacts — VT',

    domain: domainData?.json.data.id,

    // ── WHOIS availability
    has_whois:       hasWhois,
    whois_date_iso:  whoisDateISO,

    // ── WHOIS parsed
    whois_domain:       whoisDomain,
    whois_create_date:  whoisCreateDate,
    whois_expiry:       whoisExpiry,
    whois_updated:      whoisUpdated,
    whois_registrar:    whoisRegistrar,
    whois_registrar_id: whoisRegId,

    // ── Registrant (raw)
    registrant_name:    whoisRegName,
    registrant_company: whoisRegCompany,
