// ============================================================
// NODE: SSL/TLS Configuration Artifacts — VT
// ============================================================

const domainData = $input.all().find(item => item.json.data?.type === 'domain');
const ipData     = $input.all().find(item => item.json.data?.type === 'ip_address');

const domainAttr = domainData?.json.data.attributes;
const ipAttr     = ipData?.json.data.attributes;

const domainCert = domainAttr?.last_https_certificate;
const ipCert     = ipAttr?.last_https_certificate;

// ── HELPER: parse date + days remaining ──────────────────────
const daysRemaining = (dateStr) => {
  if (!dateStr) return null;
  return Math.floor((new Date(dateStr) - new Date()) / 86400000);
};

const certStatus = (days) =>
  days === null  ? 'unknown'
  : days < 0     ? 'EXPIRED'
  : days < 14    ? 'CRITICAL'
  : days < 30    ? 'WARNING'
  : days < 90    ? 'EXPIRING_SOON'
  : 'VALID';

// ── HELPER: key strength rating ──────────────────────────────
const keyStrengthRating = (algorithm, curve, keySize) => {
  if (algorithm === 'EC') {
    const strongCurves = ['secp256r1','secp384r1','secp521r1','prime256v1'];
    return strongCurves.includes(curve) ? 'STRONG' : 'WEAK';
  }
  if (algorithm === 'RSA') {
    return keySize >= 4096 ? 'STRONG'
      : keySize >= 2048    ? 'ACCEPTABLE'
      : 'WEAK';
  }
  return 'UNKNOWN';
};

// ── HELPER: issuer trust rating ──────────────────────────────
const TRUSTED_CAS = [
  'digicert', 'sectigo', 'comodo', 'globalsign', 'entrust',
  'letsencrypt', "let's encrypt", 'godaddy', 'geotrust',
  'thawte', 'rapidssl', 'amazon', 'google trust'
];

const isTrustedCA = (issuerOrg) => {
  if (!issuerOrg) return false;
  return TRUSTED_CAS.some(ca => issuerOrg.toLowerCase().includes(ca));
};

// ── 1. DOMAIN CERTIFICATE ────────────────────────────────────
const domainCertDate      = domainAttr?.last_https_certificate_date
  ? new Date(domainAttr.last_https_certificate_date * 1000).toISOString()
  : null;

const domainValidFrom     = domainCert?.validity?.not_before || null;
const domainValidUntil    = domainCert?.validity?.not_after  || null;
const domainDaysRemaining = daysRemaining(domainValidUntil);
const domainCertStatus    = certStatus(domainDaysRemaining);

const domainIssuerOrg     = domainCert?.issuer?.O  || null;
const domainIssuerCN      = domainCert?.issuer?.CN || null;
const domainIssuerC       = domainCert?.issuer?.C  || null;

const domainSubjectOrg    = domainCert?.subject?.O  || null;
const domainSubjectCN     = domainCert?.subject?.CN || null;
const domainSubjectC      = domainCert?.subject?.C  || null;
const domainSubjectST     = domainCert?.subject?.ST || null;
const domainSubjectL      = domainCert?.subject?.L  || null;

const domainKeyAlgo       = domainCert?.public_key?.algorithm || null;
const domainKeyCurve      = domainCert?.public_key?.ec?.oid   || null;
const domainKeySize       = domainCert?.public_key?.rsa?.key_size || null;
const domainKeyStrength   = keyStrengthRating(domainKeyAlgo, domainKeyCurve, domainKeySize);

const domainSANs          = domainCert?.extensions?.subject_alternative_name || [];
const domainWildcard      = domainSANs.some(s => s.startsWith('*'));
const domainThumbprint    = domainCert?.thumbprint       || null;
const domainThumbSHA256   = domainCert?.thumbprint_sha256 || null;
const domainSerial        = domainCert?.serial_number    || null;
const domainCertVersion   = domainCert?.version          || null;
const domainCertSize      = domainCert?.size             || null;
const domainSigAlgo       = domainCert?.cert_signature?.signature_algorithm || null;

const domainKeyUsage      = domainCert?.extensions?.key_usage         || [];
const domainExtKeyUsage   = domainCert?.extensions?.extended_key_usage || [];
const domainCertPolicies  = domainCert?.extensions?.certificate_policies || [];
const domainCrlUrls       = domainCert?.extensions?.crl_distribution_points || [];
const domainOcsp          = domainCert?.extensions?.ca_information_access?.OCSP || null;
const domainCaIssuers     = domainCert?.extensions?.ca_information_access?.['CA Issuers'] || null;
const domainIsCA          = domainCert?.extensions?.CA ?? null;

// OV vs DV vs EV detection via cert policies
const isEV = domainCertPolicies.some(p => p.startsWith('2.23.140.1.1'));
const isDV = domainCertPolicies.some(p => p.startsWith('2.23.140.1.2.1'));
const isOV = domainCertPolicies.some(p => p.startsWith('2.23.140.1.2.2'));
const certType = isEV ? 'EV' : isOV ? 'OV' : isDV ? 'DV' : 'UNKNOWN';

const domainCATrusted     = isTrustedCA(domainIssuerOrg);

// ── 2. IP CERTIFICATE ────────────────────────────────────────
const ipCertDate          = ipAttr?.last_https_certificate_date
  ? new Date(ipAttr.last_https_certificate_date * 1000).toISOString()
  : null;

const ipValidFrom         = ipCert?.validity?.not_before || null;
const ipValidUntil        = ipCert?.validity?.not_after  || null;
const ipDaysRemaining     = daysRemaining(ipValidUntil);
const ipCertStatus        = certStatus(ipDaysRemaining);

const ipIssuerOrg         = ipCert?.issuer?.O  || null;
const ipIssuerCN          = ipCert?.issuer?.CN || null;
const ipSubjectOrg        = ipCert?.subject?.O  || null;
const ipSubjectCN         = ipCert?.subject?.CN || null;

const ipKeyAlgo           = ipCert?.public_key?.algorithm || null;
const ipKeyCurve          = ipCert?.public_key?.ec?.oid   || null;
const ipKeySize           = ipCert?.public_key?.rsa?.key_size || null;
const ipKeyStrength       = keyStrengthRating(ipKeyAlgo, ipKeyCurve, ipKeySize);

const ipSANs              = ipCert?.extensions?.subject_alternative_name || [];
const ipThumbprint        = ipCert?.thumbprint        || null;
const ipSerial            = ipCert?.serial_number     || null;
const ipCATrusted         = isTrustedCA(ipIssuerOrg);
const ipCertPolicies      = ipCert?.extensions?.certificate_policies || [];
const ipOcsp              = ipCert?.extensions?.ca_information_access?.OCSP || null;
const ipCrlUrls           = ipCert?.extensions?.crl_distribution_points || [];

// ── 3. JARM FINGERPRINTS ─────────────────────────────────────
const domainJarm          = domainAttr?.jarm || null;
const ipJarm              = ipAttr?.jarm     || null;
const jarmMatch           = domainJarm && ipJarm && domainJarm === ipJarm;

// ── 4. CERT MISMATCH CHECK ───────────────────────────────────
// IP cert subject should match CDN/hosting provider, not domain
const ipCertMatchesDomain = ipSANs.some(s =>
  s.includes(domainData?.json.data.id || '')
);

// ── 5. ISSUES SUMMARY ────────────────────────────────────────
const issues = [];
if (!domainCert)                          issues.push('No SSL certificate found for domain');
if (domainCertStatus === 'EXPIRED')       issues.push('Domain SSL certificate is EXPIRED');
if (domainCertStatus === 'CRITICAL')      issues.push(`Domain SSL cert expires in ${domainDaysRemaining} days — CRITICAL`);
if (domainCertStatus === 'WARNING')       issues.push(`Domain SSL cert expires in ${domainDaysRemaining} days — renew soon`);
if (domainCertStatus === 'EXPIRING_SOON') issues.push(`Domain SSL cert expires in ${domainDaysRemaining} days`);
if (!domainCATrusted)                     issues.push('Domain SSL issuer not in trusted CA list');
if (domainKeyStrength === 'WEAK')         issues.push(`Weak key: ${domainKeyAlgo} ${domainKeyCurve || domainKeySize || ''}`);
if (domainIsCA === true)                  issues.push('Certificate has CA flag set — unexpected for end-entity cert');
if (certType === 'DV')                    issues.push('DV certificate — no organization validation');
if (certType === 'UNKNOWN')               issues.push('Certificate type unknown — could not determine DV/OV/EV');
if (!domainOcsp)                          issues.push('No OCSP endpoint — revocation checking may be limited');
if (domainSANs.length === 0)             issues.push('No SAN entries — certificate may be rejected by modern browsers');
if (ipCertStatus === 'EXPIRED')           issues.push('IP SSL certificate is EXPIRED');

// ── OUTPUT ───────────────────────────────────────────────────
return [{
  json: {
    _node: 'SSL/TLS Configuration Artifacts — VT',

    domain: domainData?.json.data.id,
    ip:     ipData?.json.data.id,

    // ── Domain certificate
    domain_cert_date:       domainCertDate,
    domain_valid_from:      domainValidFrom,
    domain_valid_until:     domainValidUntil,
    domain_days_remaining:  domainDaysRemaining,
    domain_cert_status:     domainCertStatus,

    domain_issuer_org:      domainIssuerOrg,
    domain_issuer_cn:       domainIssuerCN,
    domain_issuer_country:  domainIssuerC,
    domain_ca_trusted:      domainCATrusted,

    domain_subject_org:     domainSubjectOrg,
    domain_subject_cn:      domainSubjectCN,
    domain_subject_country: domainSubjectC,
    domain_subject_state:   domainSubjectST,
    domain_subject_city:    domainSubjectL,

    domain_key_algorithm:   domainKeyAlgo,
    domain_key_curve:       domainKeyCurve,
    domain_key_size:        domainKeySize,
    domain_key_strength:    domainKeyStrength,

    domain_cert_type:       certType,
    domain_cert_version:    domainCertVersion,
    domain_cert_size:       domainCertSize,
    domain_sig_algorithm:   domainSigAlgo,
    domain_serial:          domainSerial,
    domain_thumbprint:      domainThumbprint,
    domain_thumbprint_sha256: domainThumbSHA256,

    domain_san:             domainSANs,
    domain_wildcard:        domainWildcard,
    domain_key_usage:       domainKeyUsage,
    domain_ext_key_usage:   domainExtKeyUsage,
    domain_cert_policies:   domainCertPolicies,
    domain_crl_urls:        domainCrlUrls,
    domain_ocsp:            domainOcsp,
    domain_ca_issuers:      domainCaIssuers,
    domain_is_ca:           domainIsCA,

    // ── IP certificate
    ip_cert_date:           ipCertDate,
    ip_valid_from:          ipValidFrom,
    ip_valid_until:         ipValidUntil,
    ip_days_remaining:      ipDaysRemaining,
    ip_cert_status:         ipCertStatus,

    ip_issuer_org:          ipIssuerOrg,
    ip_issuer_cn:           ipIssuerCN,
    ip_subject_org:         ipSubjectOrg,
    ip_subject_cn:          ipSubjectCN,
    ip_key_algorithm:       ipKeyAlgo,
    ip_key_curve:           ipKeyCurve,
    ip_key_strength:        ipKeyStrength,
    ip_san:                 ipSANs,
    ip_thumbprint:          ipThumbprint,
    ip_serial:              ipSerial,
    ip_ca_trusted:          ipCATrusted,
    ip_cert_policies:       ipCertPolicies,
    ip_ocsp:                ipOcsp,
    ip_crl_urls:            ipCrlUrls,

    // ── JARM
    domain_jarm:            domainJarm,
    ip_jarm:                ipJarm,
    jarm_match:             jarmMatch,

    // ── Cross checks
    ip_cert_matches_domain: ipCertMatchesDomain,

    // ── Issues
    issues:      issues,
    issue_count: issues.length,
  }
}];

