const protocols = input?.protocols;

if (protocols) {
  const enabled = Object.entries(protocols)
    .filter(([, v]) => v.enabled)
    .map(([k]) => k);

  const deprecatedEnabled = Object.entries(protocols)
    .filter(([, v]) => v.enabled && v.deprecated)
    .map(([k]) => k.toUpperCase());

  const tls12 = protocols["tlsv1.2"]?.enabled === true;
  const tls13 = protocols["tlsv1.3"]?.enabled === true;

  if ((tls12 || tls13) && deprecatedEnabled.length === 0) {
    result = "Pass";
    risk = "Low";

    const modern = [];
    if (tls13) modern.push("TLS 1.3");
    if (tls12) modern.push("TLS 1.2");

    notes = `${modern.join(" and ")} enabled, legacy protocols disabled`;
  } else {
    const issues = [];

    if (!tls12 && !tls13) {
      issues.push("no modern TLS version enabled");
    }

    if (deprecatedEnabled.length > 0) {
      issues.push(`deprecated protocols enabled (${deprecatedEnabled.join(", ")})`);
    }

    notes = issues.join(", ");

    if (deprecatedEnabled.includes("SSLV2") || deprecatedEnabled.includes("SSLV3")) {
      risk = "Critical";
    } else if (deprecatedEnabled.length > 0) {
      risk = "High";
    } else {
      risk = "Medium";
    }
  }
}

return [{
  json: {
    control: "TLS protocol configuration",
    result,
    notes,
    risk
  }
}];

